INSERT INTO qdi.cnae_secao (secao_id, descricao, observacoes, hash_conteudo) VALUES
  ('A', 'AGRICULTURA, PECUÁRIA, PRODUÇÃO FLORESTAL, PESCA E AQÜICULTURA', 'Esta seção compreende a exploração ordenada dos recursos naturais vegetais e animais em ambiente natural e protegido, o que abrange as atividades de cultivo agrícola, de criação e produção animal; de cultivo de espécies florestais para produção de madeira, celulose e para proteção ambiental; de extração de madeira em florestas nativas, de coleta de produtos vegetais e de exploração de animais silvestres em seus habitats naturais; a pesca extrativa de peixes, crustáceos e moluscos e a coleta de produtos aquáticos, assim como a aqüicultura - criação e cultivo de animais e produtos do meio aquático. Também fazem parte da seção A o cultivo de produtos agrícolas e a criação de animais modificados geneticamente.  Esta seção compreende também os serviços de apoio às unidades de produção nas atividades nela contida.', 'pending_trigger'),
  ('B', 'INDÚSTRIAS EXTRATIVAS', 'Esta seção compreende as atividades de extração de minerais em estado natural: sólidos (carvão e outros minérios), líquidos (petróleo cru) e gasosos (gás natural), podendo realizar-se em minas subterrâneas, a céu aberto ou em poços. Inclui as atividades complementares de beneficiamento associado à extração, realizadas principalmente para melhorar a qualidade do produto e facilitar a comercialização, desde que o beneficiamento não altere as características físicas ou químicas dos minerais. As atividades de beneficiamento são, geralmente, executadas pela empresa mineradora junto ao local da extração. São consideradas atividades de beneficiamento: trituração, classificação, concentração, pulverização, flotação, liquefação de gás natural, etc.  As atividades extrativas são classificadas nas divisões, grupos e subclasses de acordo com o principal mineral produzido.  Esta seção compreende também os serviços industriais realizados sob contrato que fazem parte do processo produtivo das atividades desta seção, particularmente na extração de petróleo, e as atividades especializadas de apoio à exploração mineral.  Esta seção não compreende o beneficiamento de minerais não-metálicos executado fora do local da extração (seção C); a preparação do terreno para extração de minerais (seção F) e os estudos geofísicos, geológicos e semelhantes (seção M).', 'pending_trigger'),
  ('C', 'INDÚSTRIAS DE TRANSFORMAÇÃO', 'Esta seção compreende as atividades que envolvem a transformação física, química e biológica de materiais, substâncias e componentes com a finalidade de se obterem produtos novos. Os materiais, substâncias e componentes transformados são insumos produzidos nas atividades agrícolas, florestais, de mineração, da pesca e produtos de outras atividades industriais.  As atividades da indústria de transformação são, freqüentemente, desenvolvidas em plantas industriais e fábricas, utilizando máquinas movidas por energia motriz e outros equipamentos para manipulação de materiais. É também considerada como atividade industrial a produção manual e artesanal, inclusive quando desenvolvida em domicílios, assim como a venda direta ao consumidor de produtos de produção própria, como, por exemplo, os ateliês de costura. Além da transformação, a renovação e a reconstituição de produtos são, geralmente, consideradas como atividades da indústria (ex.: recauchutagem de pneus).  Os produtos novos de um estabelecimento industrial podem estar prontos para consumo ou semi-acabados, para serem usados como matéria-prima em outro estabelecimento da indústria de transformação. Por exemplo: a produção de celulose será matéria-prima para a produção de papel; por sua vez, o papel será matéria-prima para a produção de artefatos.  A extensão maior ou menor das transformações numa mesma unidade de produção varia em função de características do tipo de organização da produção, podendo apresentar-se em forma mais ou menos integrada verticalmente ou, ao contrário, através da subcontratação de outras unidades. Tanto as unidades que contratam a terceiros parte ou a totalidade de sua produção (full converter), como as unidades que operam como subcontratadas são classificadas na classe de atividade das unidades que produzem os mesmos bens por conta própria.  As indústrias de transformação, em geral, produzem bens tangíveis (mercadorias). Algumas atividades de serviços são também incluídas no seu âmbito, tais como os serviços industriais, a montagem de componentes de produtos industriais, a instalação de máquinas e equipamentos e os serviços de manutenção e reparação. Em alguns casos, a dificuldade de estabelecimento de limites na extensão de determinadas atividades leva à adoção de convenções. Alguns desses casos serão mencionados adiante.  Os serviços industriais (serviços de acabamento em produtos têxteis, tratamento de metais, etc.) constituem parte integrante da cadeia de transformação dos bens e exigem equipamentos, técnicas e habilidade específica características do processo industrial, e tanto podem ser realizados em unidades integradas como em unidades especializadas. Como classe específica na CNAE, só são identificados os serviços industriais mais importantes e somente quando são exercidos sob contrato.  A montagem das partes componentes de produtos industriais, tanto de componentes de produção própria como de terceiros, é considerada uma atividade industrial. A montagem de componentes pré-fabricados em obras de construção é classificada na indústria se a produção e a montagem são realizadas de forma integrada pela mesma unidade. Se a montagem é realizada por unidade independente especializada, é classificada na atividade de construção (seção F). Assim, a montagem no local da construção de componentes pré-fabricados produzidos por terceiros, tais como as partes integrantes de pontes, de instalações comerciais, de elevadores e de escadas rolantes, de sistemas de refrigeração, de redes elétricas e de telecomunicações e de todo tipo de estrutura, é classificada em construção.  A montagem e a instalação de máquinas e equipamentos em unidades da indústria, do comércio e dos serviços, quando realizada por unidades especializadas, são classificadas na divisão 33 (Manutenção, reparação e instalação de máquinas e equipamentos).  A montagem e instalação de máquinas e equipamentos realizada como serviço atrelado à venda por parte de unidade industrial, atacadista ou varejista, é classificada junto com a atividade principal da unidade.  As unidades que têm como atividade principal serviços de reparação e manutenção de máquinas e equipamentos industriais, comerciais e similares classificam-se em divisão específica (divisão 33). Porém as unidades de manutenção e reparação de computadores e periféricos e as unidades de manutenção e reparação de objetos pessoais e domésticos são classificadas em classes específicas da divisão 95. As unidades com atividade principal de manutenção e reparação de veículos automotores e motocicletas são classificadas em classe específica junto ao comércio de automóveis (divisão 45).  A fabricação de peças e acessórios, como regra geral, inclui-se na classe do equipamento a que estão associados às peças e acessórios, com exceção das peças e acessórios de matérias-primas específicas, como, por exemplo, de borracha, de plástico, etc., classificados na divisão referente à transformação dessas matérias-primas (borracha e plástico: divisão 22).  A recuperação de desperdícios e resíduos transformados em matérias-primas secundárias é classificada na divisão 38 (Coleta, tratamento e disposição de resíduos; recuperação de materiais). Mesmo envolvendo transformações físicas ou químicas, não é considerada como parte integrante da indústria de transformação. O objetivo primário destas atividades é o tratamento e processamento de desperdícios e resíduos, o que determina sua classificação na seção E. Porém a fabricação de produtos finais novos a partir do processamento de desperdícios é classificada na atividade de fabricação (p.ex.: a produção de prata a partir de desperdícios de filmes é considerado um processo industrial).  A fronteira entre a indústria de transformação e outras atividades nem sempre é clara. Como regra geral, as unidades da indústria manufatureira estão envolvidas com a transformação de insumos e materiais em um produto novo. A definição do que seja um produto novo, no entanto, nem sempre é objetiva, o que resulta, em muitos casos, em dificuldades na determinação dos limites do que é considerado uma atividade da indústria de transformação. Trabalha-se, nestes casos, com definições convencionadas, tal como explicitado a seguir.  Considera-se como atividade industriais: o resfriamento, pasteurização e empacotamento de leite (divisão 10); a fabricação de alimentos para animais a partir de desperdícios do abate de animais (divisão 10); o tratamento da madeira (divisão 16); a fabricação de massa de concreto preparada (divisão 23);  a impressão e correspondentes atividades de suporte (divisão 18), os serviços do laboratórios ópticos (divisão 32); a manutenção e reparação de embarcações (divisão 33); a manutenção e reparação de veículos ferroviários e de aeronaves (divisão 33).  Por outro lado não são consideradas atividades industriais: o beneficiamento de minerais em continuação à extração (seção B - divisões 07 e 08); a montagem de estruturas no local da construção, quando não realizada pelo fabricante (seção F - divisão 42); a fabricação de matérias-primas intermediárias a partir de desperdícios de alimentos e bebidas (seção E - divisão 38); a edição de livros, revistas e jornais, mesmo integrada à impressão (seção J - divisão 58); as atividades de empacotamento ou engarrafamento em lotes menores de produtos alimentícios e outros, realizadas pela unidade de comércio atacadista e varejista (seção G - divisões 46 e 47) e por unidades especializadas na prestação destes serviços para terceiros (seção N - divisão 82); a montagem de computadores para o cliente como serviço atrelado à venda pelo comércio (seção G - divisão 47); o corte de metal, madeira, vidro e outros materiais para atendimento às necessidades do cliente no comércio atacadista e varejista (seção G - divisões 46 e 47).  As divisões na seção Indústrias de transformação, em número de 24, refletem em geral diferenças em processo de produção relativos a tipos de insumo, equipamentos da produção e especialidade/qualificação de mão-de-obra.', 'pending_trigger'),
  ('D', 'ELETRICIDADE E GÁS', 'Esta seção compreende as atividades de produção, transmissão e distribuição de energia elétrica; de fornecimento de gás e de produção e distribuição de vapor e de água quente através de uma rede permanente de linhas, tubulações e dutos (instalações de infra-estrutura).  As atividades de produção, de gerenciamento da infra-estrutura e de fornecimento ao consumidor final podem ser desenvolvidas pela mesma unidade ou por unidades diferentes.  Esta seção compreende também as unidades que operam no mercado atacadista de energia elétrica.  Esta seção não compreende as unidades que operam as atividades de captação, tratamento e distribuição de água e de operação de rede de esgotamento sanitário, que são classificadas na seção E.  Esta seção não compreende a operação de transporte de gás por dutos, tipicamente feita por longa distância, conectando os produtores aos distribuidores de gás ou entre os centros urbanos (classificada em transporte por dutos: seção H - divisão 49).', 'pending_trigger'),
  ('E', 'ÁGUA, ESGOTO, ATIVIDADES DE GESTÃO DE RESÍDUOS E DESCONTAMINAÇÃO', 'Esta seção compreende as atividades de captação, tratamento e distribuição de água, seja através de uma rede permanente de tubulações e dutos (instalações de infra-estrutura) ou por outras formas de distribuição.  As atividades de produção, de gerenciamento da infra-estrutura e de fornecimento ao consumidor final podem ser desenvolvidas pela mesma unidade ou por unidades diferentes.  Esta seção compreende também a gestão de redes de esgoto (coleta e tratamento); as atividades relacionadas à gestão de resíduos de todos os tipos, p. ex., resíduos industriais ou domésticos e materiais contaminados e as atividades de descontaminação do solo, de águas subterrâneas e superficiais, de edificações contaminadas, de áreas de mineração.  O resultado final do processo de tratamento dos resíduos pode ser tanto o descarte quanto o reaproveitamento como matéria-prima secundária para outros processos de produção.', 'pending_trigger'),
  ('F', 'CONSTRUÇÃO', 'Esta seção compreende a construção de edifícios em geral (divisão 41), as obras de infra-estrutura (divisão 42) e os serviços especializados para construção que fazem parte do processo de construção (divisão 43).  A construção de edifícios compreende: a construção de edifícios para usos residenciais, comerciais, industriais, agropecuários e públicos.  Também estão compreendidas nesta seção as reformas, manutenções correntes, complementações e alterações de imóveis; a montagem de estruturas pré-fabricadas in loco para fins diversos de natureza permanente ou temporária.  A construção de obras de infra-estrutura compreende: a construção de auto-estradas, vias urbanas, pontes, túneis, ferrovias, metrôs, pistas de aeroportos, portos e redes de abastecimento de água, sistemas de irrigação, sistemas de esgoto, instalações industriais, redes de transporte por dutos (gasodutos, minerodutos, oleodutos) e linhas de eletricidade, instalações esportivas, etc.  A construção de edifícios e de obras de infra-estrutura é realizada tanto pela empresa contratada como por meio da subcontratação de terceiros. A subcontratação pode ser de partes ou do todo da obra. As unidades que assumem a responsabilidade total do desenvolvimento de projetos de construção são classificadas nesta seção.  O aluguel de equipamentos de construção e demolição com operador é classificado junto à atividade específica de construção que inclua o uso desses equipamentos.  Esta seção compreende também as atividades de incorporação de empreendimentos imobiliários que promovem a realização de projetos de engenharia civil provendo recursos financeiros, técnicos e materiais para a sua execução e posterior venda. Caso a promoção de projetos de engenharia civil seja realizada com o propósito de sua incorporação no ativo imobilizado de negócio próprio, a unidade deverá ser classificada na atividade do seu negócio, p.ex., aluguel de imóveis, indústria, hotel, etc.  Esta seção não compreende a produção de materiais de construção ou de elementos mais complexos destinados a obras de edifícios e de infra-estrutura, tais como estruturas metálicas (divisão 25), elementos pré-fabricados de madeira (divisão 16), cimento ou outros materiais pré-moldados (divisão 23), a instalação e reparação de equipamentos incorporados a edificações, como elevadores, escadas rolantes, etc., quando realizadas pelas unidades fabricantes (seção C - divisão 28), os serviços de paisagismo (seção N - divisão 81) e a retirada de entulho e refugos de obra e de demolições (seção E - divisão 38).', 'pending_trigger'),
  ('G', 'COMÉRCIO; REPARAÇÃO DE VEÍCULOS AUTOMOTORES E MOTOCICLETAS', 'Esta seção compreende as atividades de compra e venda de mercadorias, sem transformação significativa, inclusive quando realizadas sob contrato. Inclui também a manutenção e reparação de veículos automotores.   A venda sem transformação inclui operações (ou manipulações) que são usualmente associadas ao comércio, tais como: montagem, mistura de produtos, engarrafamento, empacotamento, fracionamento etc., quando realizadas pela própria unidade comercial.  O comércio de mercadorias organiza-se em dois segmentos: atacado e varejo  O comércio atacadista revende mercadorias novas ou usadas, sem transformação, a varejistas, a usuários industriais, agrícolas, comerciais, institucionais e profissionais, ou a outros atacadistas; ou atua como representante comercial ou agente do comércio na compra ou venda de mercadorias a esses usuários.   No comércio atacadista, distinguem-se dois tipos de atividades: o atacadista que compra a mercadoria que revende, o atacadista representante ou agente do comércio, que, sob contrato, comercializa em nome de terceiros, inclusive operando o mercado eletrônico via internet. Estas atividades são desenvolvidas por comerciantes atacadistas, distribuidores de produtos industriais, exportadores e importadores, comissários, agentes de fábricas, compradores itinerantes e cooperativas que comercializam produtos agrícolas.  O comércio varejista revende mercadorias novas e usadas, sem transformação, principalmente ao público em geral, para consumo ou uso pessoal ou doméstico.  As unidades comerciais que revendem tanto para empresas como para o público em geral devem ser classificadas como varejistas.', 'pending_trigger'),
  ('H', 'TRANSPORTE, ARMAZENAGEM E CORREIO', 'Esta seção compreende as atividades de transporte de passageiros ou mercadorias, nas modalidades ferroviária, rodoviária, aquaviária, aérea e dutoviária, as atividades de armazenamento e carga e descarga e as atividades de correio, de malote e de entrega.  Também incluídas nesta seção as atividades auxiliares dos transportes, tais como a gestão e operação de terminais rodoviários, ferroviários, portuários e aeroportuários e atividades correlatas.  O fretamento de equipamento de transporte com condutor ou operador é considerado um serviço de transporte e como tal, inclui-se nesta seção.  Dois conceitos são usuais nas análises dos transportes: o conceito de transporte regular versus não regular para diferenciar os serviços de transporte de passageiros abertos ao público em geral e com itinerário e horários fixos dos serviços de transporte de uso privativo de um grupo de clientes (uma ou mais pessoas), em que o itinerário e horário são fixados pelo cliente, e o conceito de transporte urbano e não urbano. A CNAE define categorias separadas para o transporte coletivo, com itinerário fixo (regular) para o transporte de passageiros nas modalidades rodoviária, aquaviária e aérea. Para a delimitação do espaço urbano e não urbano do transporte de passageiros nas modalidades rodoviária, ferroviária e aquaviária (vias internas), a CNAE recorre à organização político-administrativa da regulamentação destes transporte na economia brasileira, trabalhando com categorias específicas para identificação do transporte municipal e intermunicipal na região metropolitana, para compor o espaço urbano, e do transporte intermunicipal fora da região metropolitana, interestadual e internacional para compor o espaço não urbano.  Esta seção não compreende a locação de automóveis e outros meios de transporte sem condutor ou operador (seção N); a manutenção e reparação de veículos automotores (seção G); de veículos ferroviários, embarcações e aeronaves (seção C); as atividades de agências de viagens (seção N)', 'pending_trigger'),
  ('I', 'ALOJAMENTO E ALIMENTAÇÃO', 'Esta seção compreende as atividades de alojamento de curta duração e os serviços de alimentação.  Os serviços de alojamento se distinguem dos de locação de imóveis pela curta duração da disponibilidade do local de alojamento, salvo em casos de alojamentos coletivos (pensionatos, casas de estudante), tradicionalmente tratados dentro deste segmento.  Os serviços de alimentação têm como característica o preparo das refeições para consumo imediato, com ou sem serviço completo (para efeito de classificação, entende-se como serviço completo todas as unidades que tem serviço de mesa, independente de que o pessoal encarregado de servir as refeições tenha outras funções dentro da unidade econômica), a preparação de alimentos por encomenda e a preparação de bebidas para consumo imediato. Não inclui a preparação de alimentos que não seja para consumo imediato (divisão 10) e, também, a venda de refeições e bebidas que não seja para consumo imediato (seção G).  Os estabelecimentos que combinam serviços de alimentação e espetáculos artísticos, devem ser classificados por sua atividade básica. Assim sendo, uma sala de espetáculos mesmo com serviço de bar é classificada em atividades de espetáculo e um bar ou restaurante mesmo com música, em serviços de alimentação. No caso de um estabelecimento hoteleiro com restaurante, a unidade é classificada em atividade de alojamento.', 'pending_trigger'),
  ('J', 'INFORMAÇÃO E COMUNICAÇÃO', 'Esta seção compreende as atividades de criação e colocação de produtos com conteúdo de informação em mídias que possibilitam a sua disseminação; as atividades de transmissão desses produtos por sinais analógicos ou digitais (através de meios eletrônicos, sem fio, óticos ou outros meios); e as atividades de provisão dos serviços e/ou operação de infra-estrutura que possibilitam a transmissão e o armazenamento desses produtos.  Os produtos com conteúdo de informação não são necessariamente tangíveis e, diferentemente de produtos tradicionais, não estão associados a um formato específico. O valor desses produtos está no conteúdo e não no formato do suporte no qual são colocados para serem distribuídos. Por exemplo, um filme pode ser passado no cinema, na televisão ou copiado em vídeo para aluguel ou venda ao público. Algumas das atividades compreendidas nesta seção envolvem direitos autorais.  As principais atividades desta seção são as de edição e de edição integrada à impressão (divisão 58), as atividades cinematográficas e as de gravação de som e edição de música (divisão 59), as atividades de rádio e de televisão (divisão 60), as atividades de telecomunicações (divisão 61), as atividades de tecnologia da informação (divisão 62) e as outras atividades de prestação de serviços de informação (divisão 63).  As atividades de edição incluem a aquisição de direitos autorais de produtos com conteúdo de informação, bem como as atividades que permitem a disseminação desse conteúdo para o público em geral, ou seja, a reprodução e a distribuição desse conteúdo. Estão incluídas nesta seção todas as formas viáveis de edição de produtos com conteúdo de informação (impressa, eletrônica ou sonora, na internet e em produtos multimídia, como CDs, DVDs, etc.).  As atividades relacionadas à produção e distribuição de programação de televisão abrangem as divisões 59, 60 e 61, refletindo as diferentes etapas deste processo. Atividades como a produção de filmes cinematográficos e seriados de televisão estão compreendidas na divisão 59, enquanto a criação de uma programação completa de um canal de televisão, que inclui tanto os produtos que resultam das atividades da divisão 59 como a programação de televisão ao vivo, faz parte da divisão 60. A divisão 60 também inclui atividades de difusão dessa programação pelo próprio produtor. A distribuição de programação de televisão por terceiros, isto é, sem incluir nenhuma alteração no conteúdo, é incluída na divisão 61. A atividade de distribuição de conteúdo (telecomunicações), tratada na divisão 61, compreende a difusão por cabos, microondas ou satélites ou por uma combinação dessas tecnologias.', 'pending_trigger'),
  ('K', 'ATIVIDADES FINANCEIRAS, DE SEGUROS E SERVIÇOS RELACIONADOS', 'Esta seção compreende as unidades voltadas primordialmente à realização de transações financeiras, isto é, transações envolvendo a criação, liquidação e troca de propriedade de ativos financeiros. Também compreende as atividades de seguros, capitalização, resseguros, previdência complementar, planos de saúde e as atividades de serviços de apoio às transações financeiras e às atividades de seguros. O Banco Central, como autoridade monetária do país, também está enquadrado nesta seção.  As atividades de intermediação financeira são exercidas primordialmente pelas instituições do Sistema Financeiro Nacional (SFN) tal como definidas pelas leis nº 4.595/64, que atribui ao Banco Central do Brasil (BACEN) e à Comissão de Valores Mobiliários (CVM) a competência para autorizar, regulamentar e fiscalizar o exercício da intermediação financeira, e nº 4.728/ 65, que disciplinou o mercado de capitais definindo atividades auxiliares. Mas também inclui unidades fora do SFN que exercem atividades que envolvem a criação, coleta e redistribuição de fundos financeiros (exemplos: sociedades de fomento mercantil – factoring, caixas de financiamento de corporações, concessão de crédito pelas OSCIP, etc.).  Esta seção compreende também as instituições de Seguros, regulamentadas pela Superintendência Nacional de Seguros Privados (SUSEP) e pelo Conselho Gestor da Previdência Complementar, as sociedades de capitalização, previdência complementar, os planos de saúde e os serviços estritamente vinculados às atividades financeiras e de seguros.  Esta seção também inclui as atividades relacionadas à propriedade de ativos, tais como as atividades das empresas holdings, as atividades de fundos de investimento e outras entidades financeiras.', 'pending_trigger'),
  ('L', 'ATIVIDADES IMOBILIÁRIAS', 'Esta seção compreende as atividades de gestores de propriedade imobiliária como as de: proprietários de imóveis, agentes e corretores imobiliários que atuam nas atividades de compra, venda e aluguel de imóveis e outros serviços relacionados como a avaliação de imóveis para qualquer finalidade.  Esta seção compreende também as atividades de administração de condomínios, shopping centers e outros imóveis. As atividades compreendidas nesta seção podem ser desenvolvidas pelo proprietário do imóvel ou por terceiros sob contrato ou corretagem.', 'pending_trigger'),
  ('M', 'ATIVIDADES PROFISSIONAIS, CIENTÍFICAS E TÉCNICAS', 'Esta seção compreende as atividades especializadas profissionais, científicas e técnicas. Estas atividades requerem uma formação profissional específica normalmente com elevado nível de qualificação e treinamento (em geral educação universitária). O conhecimento especializado (expertise) é o principal elemento colocado à disposição do cliente.  Estas atividades compreendem atividades jurídicas, contabilidade, arquitetura e engenharia, pesquisa científica, publicidade, pesquisa de mercado, fotografia profissional, consultorias e serviço veterinário.', 'pending_trigger'),
  ('N', 'ATIVIDADES ADMINISTRATIVAS E SERVIÇOS COMPLEMENTARES', 'Esta seção compreende uma variedade de atividades rotineiras de apoio ao funcionamento de empresas e organizações.  As atividades de apoio administrativo geralmente compreendem: contratação e colocação de pessoas em empresas clientes; preparo de documentos e outros serviços de escritório; serviços de teleatendimento; serviços de cobrança para clientes; organização de viagens; e serviços de envasamento e empacotamento sob contrato.  Compreendem ainda os seguintes tipos de serviços: locação e leasing operacional de meios de transporte sem condutor e máquinas e equipamentos sem operador; aluguel de objetos pessoais e domésticos; gestão de ativos intangíveis não-financeiros; vigilância; limpeza de prédios e domicílios e atividades paisagísticas.  As atividades desenvolvidas por unidades compreendidas nesta seção geralmente são serviços terceirizados. A tendência atual da maioria das empresas é terceirizar as atividades administrativas e os serviços de apoio ao seu funcionamento, contratando-os de empresas especializadas que os fornecem a uma variedade de clientes.', 'pending_trigger'),
  ('O', 'ADMINISTRAÇÃO PÚBLICA, DEFESA E SEGURIDADE SOCIAL', 'Esta seção compreende as atividades que, por sua natureza, são normalmente realizadas pela Administração Pública e, como tal, são atividades essencialmente não-mercantis, compreendendo a administração geral (o executivo, o legislativo, a administração tributária, etc., nas três esferas de governo) e a regulamentação e fiscalização das atividades na área social e da vida econômica do país (grupo 84.1); as atividades de defesa, justiça, relações exteriores, etc. (grupo 84.2); e a gestão do sistema de seguridade social obrigatória (grupo 84.3).  A natureza jurídica não é em si mesma um fator determinante para a classificação de uma unidade nesta seção, e sim o fato de exercer atividade que, por sua natureza especifica, é de prerrogativa do Estado. Assim algumas instituições públicas que exercem atividades compreendidas em outras categorias da CNAE 2.0 são classificadas nas classes correspondentes aos serviços prestados, e não na divisão 84, como é o caso das atividades de ensino e de saúde, que, mesmo quando exercidas pelo Estado, são classificadas nas divisões correspondentes (85 e 86).  Os órgãos de regulamentação, controle ou coordenação destas atividades, no entanto, são classificados na divisão 84. Da mesma forma, algumas atividades descritas na divisão 84 podem ser exercidas por unidades não-governamentais. A terceirização de serviços ou parte de serviços tradicionalmente executados pelo Estado pode levar à presença de entidades empresariais e instituições privadas sem fins lucrativos em atividades compreendidas na divisão 84.  A divisão 84 inclui unidades que são entidades criadas por lei, com personalidade jurídica própria, que realizam atividades de suporte à administração pública com a finalidade de facilitar a gestão de recursos públicos, dando suporte em áreas de função típica do Estado, na execução de ações tais como: compras de bens e serviços, contratação de serviços com a finalidade de desenvolvimento econômico e social, administração e gestão de recursos humanos, etc. Funcionam como apêndice de órgãos da Administração Pública brasileira e devem ser classificados nas classes onde estão enquadrados os órgãos a que se ligam.', 'pending_trigger'),
  ('P', 'EDUCAÇÃO', 'Esta seção compreende as unidades que realizam atividades de ensino público e privado, em qualquer nível e para qualquer finalidade, na forma presencial ou à distância, por meio de rádio, televisão, por correspondência ou outro meio de comunicação. Inclui tanto a educação ministrada por diferentes instituições do sistema regular de educação, nos seus diferentes níveis, como o ensino profissional e a educação continuada (exemplos: cursos de idiomas, cursos de aprendizagem e treinamento gerencial e profissional).  Nesta seção estão incluídas as academias militares, escolas em prisão, etc., em seus respectivos níveis.  A Educação Especial oferecida para pessoas portadoras de necessidades especiais, preferencialmente na rede regular de ensino, está incluída nas três etapas da educação básica (educação infantil, ensino fundamental e ensino médio).  A educação de jovens e de adultos, modalidade de educação escolar, deve ser classificada no nível de ensino oferecido (fundamental ou médio). O ensino supletivo faz parte do ensino fundamental e médio.  A educação à distância não é um tipo de ensino e sim, uma maneira de ministrá-lo, sendo cabível na educação seriada (educação básica e educação superior) e na educação profissional e continuada.  As creches, de todos os tipos, estão incluídas na educação.  A desagregação das categorias nesta seção leva em consideração a Lei de Diretrizes e Bases (Lei nº 9.394 de 1996).  O ensino profissionalizante está destacado dos demais, segundo níveis técnico e tecnológico, seguindo as Diretrizes Curriculares Nacionais para a Educação Profissional de Nível Técnico, definidas na Resolução do Conselho Nacional de Educação/Comissão de Educação Básica (CNE/CEB) nº 04/99.  Quando uma instituição atua em mais de um nível da educação seriada, é classificada na classe CNAE correspondente ao nível mais elevado.  Esta seção compreende também o ensino de esportes, arte e cultura e as atividades de apoio à educação.', 'pending_trigger'),
  ('Q', 'SAÚDE HUMANA E SERVIÇOS SOCIAIS', 'Esta seção abrange as atividades de atenção à saúde humana e de serviços sociais. As atividades de atenção à saúde humana cobrem todas as formas de serviços relacionados à saúde humana prestados em hospitais, ambulatórios, consultórios, clínicas, centros de assistência psicossocial, unidades móveis de atendimento a urgências e remoções e, também, os serviços de saúde prestados nos domicílios.  Esta seção compreende também as atividades de apoio à gestão dos estabelecimentos de saúde e as atividades de práticas integrativas e complementares à saúde humana.  As atividades de serviços sociais são as de assistência a indivíduos ou famílias e são realizadas por agências de governo ou por instituições privadas e, também, são prestadas nos domicílios. Essas atividades podem incluir ou não alojamento, serviços médicos e serviços de educação desde que estes não sejam os principais serviços oferecidos.', 'pending_trigger'),
  ('R', 'ARTES, CULTURA, ESPORTE E RECREAÇÃO', 'Esta seção compreende uma ampla variedade de atividades destinadas a satisfazer os interesses culturais, de entretenimento e recreativos da população. Compreende a produção e promoção de artes cênicas e espetáculos, inclusive de atuações ao vivo, as bibliotecas, arquivos, museus, jardins zoológicos e botânicos, a exploração de jogos de azar e apostas, as atividades esportivas, de recreação e lazer.', 'pending_trigger'),
  ('S', 'OUTRAS ATIVIDADES DE SERVIÇOS', 'Esta seção compreende uma ampla variedade de serviços pessoais; serviços de organizações associativas patronais, empresariais, profissionais, sindicais, de defesa de direitos sociais, religiosas, políticas, etc.; atividades de manutenção e reparação de equipamentos de informática, de comunicação e de objetos pessoais e domésticos. Os serviços pessoais incluem: lavanderias; cabeleireiros e outras atividades de tratamento de beleza; clínicas de estética; atividades funerárias; e serviços religiosos.', 'pending_trigger'),
  ('T', 'SERVIÇOS DOMÉSTICOS', 'Esta seção compreende as atividades realizadas nos domicílios por empregados contratados pelas famílias.', 'pending_trigger'),
  ('U', 'ORGANISMOS INTERNACIONAIS E OUTRAS INSTITUIÇÕES EXTRATERRITORIAIS', 'Esta seção compreende as atividades de enclaves diplomáticos ou similares (como embaixadas, consulados, representações de organismos internacionais), onde se enquadram os organismos localizados no país dentro do conceito de extraterritorialidade, ou seja, o local físico em que operam não é considerado território sob as leis nacionais.', 'pending_trigger')
INSERT INTO qdi.cnae_divisao (divisao_id, secao_id, descricao, observacoes, hash_conteudo) VALUES
  ('01', 'A', 'AGRICULTURA, PECUÁRIA E SERVIÇOS RELACIONADOS', 'Esta divisão compreende o cultivo de lavouras e a criação e produção animal.  No cultivo de lavouras são identificados quatro segmentos (grupos): produção de lavouras temporárias (grupo 01.1); horticultura e floricultura (grupo 01.2); produção de lavouras permanentes (grupo 01.3); produção de sementes e mudas certificadas (grupo 01.4), onde estão incluídos os processos de cultivo tradicional, orgânico, bem como o cultivo de plantas modificadas geneticamente.  Na criação e produção animal identifica-se um único grupo: pecuária (grupo 01.5), onde também se inclui a criação de animais modificados geneticamente.  A produção de sementes e mudas das lavouras, quando associada ao cultivo, classifica-se na mesma classe CNAE do cultivo. As unidades especializadas na produção de sementes e mudas certificadas, inclusive modificadas geneticamente, são classificadas em categoria própria (grupo 01.4).  O processamento, na unidade de produção agrícola, de produtos agrícolas ou pecuários provenientes de produção própria classifica-se no mesmo código da atividade da produção. Quando o processamento é desempenhado por terceiros, classifica-se na seção C - indústrias de transformação.  Esta divisão compreende também a caça tradicional e com armadilha, as atividades de apoio à agricultura e à pecuária e às atividades de pós-colheita.  As atividades de apoio à agricultura - preparo do solo, plantio, colheita, etc. - e de apoio à pecuária - manejo dos animais, inseminação artificial, etc. - executadas sob contrato estão incluídas nesta divisão em categorias específicas de serviços de apoio à agricultura (01.61-0) e à pecuária (01.62-8). Estes serviços, quando executados em unidades de produção agrícola ou de pecuária com recursos próprios, ficam incluídos na mesma classe onde se classifica a unidade de produção.  Por atividades pós-colheita (01.63-6) entende-se a preparação primária de produtos agrícolas para o mercado (limpeza, ornamentação, classificação, desinfecção).', 'pending_trigger'),
  ('02', 'A', 'PRODUÇÃO FLORESTAL', 'Esta divisão compreende o cultivo de espécies florestais, a produção de madeira em toras e a exploração de produtos florestais não-madeireiros.  Compreende também a produção de mudas florestais, os produtos da madeira resultantes de pequeno processamento - lenha, carvão vegetal, lascas de madeira - assim como a madeira utilizada sem processamento - moirões, estacas e postes.   Estas atividades podem ocorrer em florestas plantadas ou nativas.', 'pending_trigger'),
  ('03', 'A', 'PESCA E AQÜICULTURA', 'Esta divisão compreende a pesca e a criação de animais aquáticos, abrangendo o uso dos recursos pesqueiros em águas marinhas, salobras e em água doce, objetivando a captura de peixes, crustáceos, moluscos e de outros organismos ou produtos aquáticos (plantas aquáticas, pérolas, esponjas, outros).  Também compreende as atividades normalmente integradas ao processo de produção na aqüicultura (produção de sementes de ostras para produção de pérolas).  Esta divisão não compreende a construção e reparação de navios e barcos (divisão 30), a atividade de pesca esportiva ou recreativa (divisão 85) e o processamento de peixes, crustáceos e moluscos realizado em estabelecimento industrial ou em barco-fábrica (divisão 10).', 'pending_trigger'),
  ('05', 'B', 'EXTRAÇÃO DE CARVÃO MINERAL', 'Esta divisão compreende as atividades de extração de carvão mineral e os beneficiamentos de carvão mineral tais como limpeza, classificação, pulverização, etc., associados ou em continuação à extração.  Esta divisão não compreende a atividade de escavação de minas quando não realizada pela empresa de exploração mineral (divisão 43).', 'pending_trigger'),
  ('06', 'B', 'EXTRAÇÃO DE PETRÓLEO E GÁS NATURAL', 'Esta divisão compreende a extração de petróleo e gás natural e a extração de xisto e de areias betuminosas.  Esta divisão compreende também as atividades de preparação e operação dos campos de petróleo e de gás, tais como: perfuração dirigida e reperfuração, perfuração inicial, reparação e desmantelamento de torres de perfuração, cementação dos tubos dos poços e todas as atividades de preparação do petróleo e gás realizadas no local pelos operadores de poços até o momento da remessa para fora do campo de petróleo, realizadas no local, pelos operadores de poços.  Esta divisão não compreende os serviços de apoio requeridos pela perfuração e operações de campo realizados sob contrato (divisão 09) e a atividade de escavação de minas quando não realizada pela empresa de exploração mineral (divisão 43).', 'pending_trigger'),
  ('07', 'B', 'EXTRAÇÃO DE MINERAIS METÁLICOS', 'Esta divisão compreende a extração, subterrânea e a céu aberto, de minerais metálicos e as atividades de beneficiamento associadas e em continuação à extração (moagem, trituração, classificação, concentração, pelotização, sinterização, etc.).  Os minerais metálicos compreendidos nesta divisão são: ferrosos (ferro); não-ferrosos (alumínio, estanho, cobre, manganês, vanádio, etc.) e os preciosos (ouro, prata, platina).  Esta divisão compreende também a extração de minerais radioativos (areia monazítica ou monazita, urânio e tório).  Esta divisão não compreende as atividades de apoio à extração de minerais metálicos, realizadas sob contrato (divisão 09) e as atividades de escavação de minas quando não realizadas pela empresa de exploração mineral (divisão 43).', 'pending_trigger'),
  ('08', 'B', 'EXTRAÇÃO DE MINERAIS NÃO-METÁLICOS', 'Esta divisão compreende as atividades de extração de minerais não-metálicos em pedreiras, em depósitos aluviais, rochas e terras sedimentares. Os produtos compreendidos nesta divisão são, normalmente, usados em construção (areias, pedras), para a fabricação de outros materiais (barro, gesso), e para a fabricação de produtos químicos (fosfatos e sulfatos naturais).  Esta divisão compreende também as atividades de beneficiamento, associado ou em continuação à extração (corte, limpeza, secagem, etc.) e as atividades de refino do sal marinho.  Esta divisão não compreende as atividades das unidades integradas verticalmente que processam minerais não-metálicos, como, por exemplo, as plantas de cimento e de materiais cerâmicos (divisão 23); as atividades de apoio à extração de minerais não-metálicos realizadas sob contrato (divisão 09); a atividade de escavação de minas quando não realizada pela empresa de exploração mineral (divisão 43).', 'pending_trigger'),
  ('09', 'B', 'ATIVIDADES DE APOIO À EXTRAÇÃO DE MINERAIS', 'Esta divisão compreende as atividades especializadas de apoio à extração mineral executadas sob contrato. Inclui os serviços feitos por métodos de prospecção tradicionais (p.ex., a retirada de amostras), por observações geológicas, bem como por perfurações e reperfurações com objetivo de análise de campos de petróleo e de outras áreas de mineração.  Esta divisão não compreende as atividades de escavação de minas quando não realizadas pela empresa de exploração mineral (divisão 43) e os estudos geológicos e de prospecção que se baseiam na realização de medições e observações de superfície para a obtenção de informações sobre a estrutura do subsolo, localização de campos de petróleo e gás natural, minerais e depósitos subterrâneos de água (divisão 71).', 'pending_trigger'),
  ('10', 'C', 'FABRICAÇÃO DE PRODUTOS ALIMENTÍCIOS', 'Esta divisão compreende o processamento e transformação de produtos da agricultura, pecuária e pesca em alimentos para uso humano e animal. Esta divisão está organizada por atividades que processam e transformam diferentes tipos de produtos como carnes, pescados, leite, frutas e legumes, gorduras e óleos, grãos e produtos de moagem, etc.  Esta divisão compreende também a fabricação de alimentos dietéticos, alimentos enriquecidos, complementos alimentares e semelhantes.  Esta divisão não compreende os estabelecimentos que executam algum processamento no produto alimentício, visando exclusivamente a facilitar a comercialização, como, por exemplo, os açougues e peixarias (Seção G) e as padarias com venda direta ao público (divisão 47).', 'pending_trigger'),
  ('11', 'C', 'FABRICAÇÃO DE BEBIDAS', 'Esta divisão compreende a fabricação de bebidas de todos os tipos: alcoólicas (obtidas por fermentação ou destilação), não-alcoólicas (refrigerantes e refrescos), as águas envasadas e a fabricação de xaropes para a fabricação de refrigerantes e refrescos.  Esta divisão não compreende a fabricação de sucos de frutas prontos para beber (divisão 10); o engarrafamento de bebidas associado ao comércio atacadista (divisão 46) e o engarrafamento de bebidas efetuado sob contrato (divisão 82).', 'pending_trigger'),
  ('12', 'C', 'FABRICAÇÃO DE PRODUTOS DO FUMO', 'Esta divisão compreende a fabricação de cigarros, cigarrilhas e outros derivados do fumo.  Esta divisão compreende também o fumo processado industrialmente (destalamento e outros beneficiamentos elaborados em unidades industriais) e a fabricação de filtros para cigarros.  Esta divisão não compreende o cultivo do fumo, bem como o beneficiamento inicial (divisão 01)', 'pending_trigger'),
  ('13', 'C', 'FABRICAÇÃO DE PRODUTOS TÊXTEIS', 'Esta divisão compreende as atividades de preparação das fibras têxteis, a fiação e a tecelagem (plana ou não). As fibras têxteis podem ser naturais (algodão, seda, linho, lã, rami, juta, sisal, etc.) ou químicas (artificiais e sintéticas). A preparação das fibras têxteis naturais consiste em processos tais como: lavagem, carbonização, cardação, penteação e outras.  A fiação é um processo intermediário na cadeia produtiva têxtil e tem como insumo as fibras naturais e as fibras químicas.  A fabricação de tecidos é feita a partir de técnicas distintas: a tecelagem de tecidos planos é resultantes do entrelaçamento de dois conjuntos de fios que se cruzam em ângulo reto; a malharia é resultado da formação de laços que se interpenetram e se apóiam lateral e verticalmente, provenientes de um ou mais fios e o tecido não tecido (non-woven) é obtido diretamente de camadas de fibras que se prendem umas às outras por meios físicos e químicos, formando uma folha contínua, como p.ex..: feltros e enchimentos.  Esta divisão compreende também as atividades de acabamento de fios, tecidos e artigos têxteis e do vestuário. As atividades de acabamento podem realizar-se em fibras, fios e tecidos e constituem-se em uma série de operações que preparam os produtos têxteis para o uso a que se destinam. Podem ser: alvejamento, tingimento, estamparia e outros.  Esta divisão não compreende a fabricação de fibras artificiais e sintéticas que são produzidas na indústria química (divisão 20), a fabricação de fibra de vidro (divisão 23) e a confecção de artefatos do vestuário (divisão 14).', 'pending_trigger'),
  ('14', 'C', 'CONFECÇÃO DE ARTIGOS DO VESTUÁRIO E ACESSÓRIOS', 'Esta divisão compreende a confecção, por costura, de roupas para adultos e crianças, de qualquer material (tecidos planos e de malha, couros, etc.) e para qualquer uso (roupas íntimas, sociais, profissionais, etc.), confeccionadas em série ou sob medida.  Esta divisão compreende também os serviços de confecção (corte, costura, etc.), os serviços de facção e a confecção de acessórios do vestuário para uso pessoal.  Esta divisão não compreende a reparação ou conserto de peças do vestuário (divisão 95) e a fabricação de roupas de borracha ou de material plástico unidas por adesivos e outra forma que não seja costura (divisão 22).', 'pending_trigger'),
  ('15', 'C', 'PREPARAÇÃO DE COUROS E FABRICAÇÃO DE ARTEFATOS DE COURO, ARTIGOS PARA VIAGEM E CALÇADOS', 'Esta divisão compreende o curtimento e outras preparações de couros e peles e a fabricação de artefatos de couro, a fabricação de substitutos do couro, a fabricação de bolsas e de artigos para viagem de qualquer material.  Esta divisão compreende também a fabricação de calçados para todos os usos e suas partes, de qualquer material e por qualquer processo  Esta divisão não compreende a fabricação de calçados ortopédicos (divisão 32).', 'pending_trigger'),
  ('16', 'C', 'FABRICAÇÃO DE PRODUTOS DE MADEIRA', 'Esta divisão compreende, a fabricação de madeira serrada, laminada, compensada, prensada e aglomerada e de produtos de madeira para construção, para embalagem, para uso industrial, comercial e doméstico.  Esta divisão compreende também a imunização da madeira e a fabricação de produtos de cortiça, bambu, vime, junco, palha e outros materiais trançados.  Esta divisão não compreende a fabricação de móveis de madeira, bambu e materiais semelhantes (divisão 31).', 'pending_trigger'),
  ('17', 'C', 'FABRICAÇÃO DE CELULOSE, PAPEL E PRODUTOS DE PAPEL', 'Esta divisão compreende a fabricação de polpa, papel, papel-cartão e papelão e de produtos fabricados com papel, papel-cartão ou papelão ondulado, mesmo impressos, desde que a impressão de informação não seja a finalidade principal do produto  Esta divisão compreende também a fabricação de polpa moldada (produtos obtidos a partir de pastas químicas ou mecânicas e/ou aparas, na forma desejada e para uso específico)', 'pending_trigger'),
  ('18', 'C', 'IMPRESSÃO E REPRODUÇÃO DE GRAVAÇÕES', 'A atividade de impressão compreende a contratação de um produto industrial final pronto, onde o contratado é responsável por todo o processo, desde a aquisição da matéria-prima até o produto final.  Esta divisão compreende a impressão, por qualquer processo (ofsete, flexografia, serigrafia, etc), em qualquer material (papel, plástico, couro, tecidos, etc.) de jornais, livros, revistas e outros periódicos, formulários, cartões comemorativos, etc. e as atividades de apoio como pré-impressão, acabamentos, etc.  Esta divisão compreende também a reprodução de mídia gravada, tais como CDs, gravações de vídeo, softwares, etc.  Esta divisão não compreende as atividades de edição e de edição integrada à impressão (divisão 58).', 'pending_trigger'),
  ('19', 'C', 'FABRICAÇÃO DE COQUE, DE PRODUTOS DERIVADOS DO PETRÓLEO E DE BIOCOMBUSTÍVEIS', 'Esta divisão compreende a transformação de carvão mineral em coquerias independentes, o refino do petróleo, a fabricação de álcool para qualquer fim, a fabricação de biodiesel a partir da transesterificação de óleos vegetais ou gorduras animais e a fabricação de outros biocombustíveis.  A atividade de refino compreende os beneficiamentos do petróleo cru para a obtenção de produtos como combustíveis (gasolina, óleo diesel, querosene), parafina, asfalto, nafta, etc.  A atividade de fabricação do álcool inclui-se nesta divisão, considerando que seu uso principal é como combustível e se constitui em uma das mais importantes alternativas energéticas no país.  Esta divisão compreende também a fabricação de produtos a partir de minerais betuminosos, a fabricação de produtos derivados de petróleo produzidos fora de refinarias a atividade de formulação de combustíveis líquidos a partir da mistura de correntes de hidrocarbonetos a atividade de rerrefino de óleos lubrificantes usados.  Esta divisão não compreende a extração de petróleo e gás natural (divisão 06); a fabricação de produtos petroquímicos (divisão 20).', 'pending_trigger'),
  ('29', 'C', 'FABRICAÇÃO DE VEÍCULOS AUTOMOTORES, REBOQUES E CARROCERIAS', 'Esta divisão compreende a fabricação de veículos automotores para transporte de pessoas e mercadorias e a fabricação de cabines, carrocerias, reboques e semi-reboques para veículos automotores.  Esta divisão compreende também a fabricação de peças e acessórios, de material elétrico e eletrônico, de bancos e estofados para os veículos automotores produzidos nesta divisão e a fabricação de contêineres.  Esta divisão não compreende a manutenção e reparação de veículos automotores (divisão 45).', 'pending_trigger'),
  ('20', 'C', 'FABRICAÇÃO DE PRODUTOS QUÍMICOS', 'Esta divisão compreende a transformação de matérias-primas orgânicas ou inorgânicas por processos químicos e a formulação de produtos e a produção de gases industriais, fertilizantes, resinas e fibras, defensivos agrícolas e desinfestantes domissanitários, produtos de limpeza e perfumaria, tintas, explosivos e outros produtos químicos.  Esta divisão compreende também a fabricação de produtos petroquímicos básicos e intermediários.  A química fina e suas especialidades, com especificidades tecnológicas próprias, mesmo não compondo um segmento específico da CNAE, pode ser reconstituída, por aproximação, através da agregação das seguintes subclasses de atividades: (2029-1/00), (2051-7/00), (2093-2/00), (2094-1/00), (2110-6/00), (2121-1/01), (2121-1/02), (2121-1/03) e (2122-0/00).', 'pending_trigger'),
  ('21', 'C', 'FABRICAÇÃO DE PRODUTOS FARMOQUÍMICOS E FARMACÊUTICOS', 'Esta divisão compreende a fabricação de produtos farmoquímicos, a fabricação de medicamentos e de outros produtos farmacêuticos, tais como: curativos impregnados com qualquer substância, preparações anti-sépticas, etc.  Esta divisão não compreende a fabricação de alimentos dietéticos, alimentos enriquecidos, complementos alimentares e semelhantes (divisão 10).', 'pending_trigger'),
  ('22', 'C', 'FABRICAÇÃO DE PRODUTOS DE BORRACHA E DE MATERIAL PLÁSTICO', 'Esta divisão compreende a fabricação de produtos de borracha ou de material plástico. As atividades desta divisão são determinadas pela matéria-prima utilizada.  Esta divisão não compreende a fabricação de artigos do vestuário confeccionados através de costura, mesmo que a borracha ou o material plástico sejam o componente principal desses produtos (divisão 14) e a fabricação de calçados de borracha ou de material plástico (divisão 15).', 'pending_trigger'),
  ('23', 'C', 'FABRICAÇÃO DE PRODUTOS DE MINERAIS NÃO-METÁLICOS', 'Esta divisão compreende a fabricação de produtos relacionados a substâncias minerais, como a fabricação de vidro e produtos de vidro, a fabricação de produtos cerâmicos ou de barro cozido, de cimento, de gesso e de materiais semelhantes.  Esta divisão compreende também o aparelhamento e outros trabalhos em pedras e o beneficiamento de minerais não-metálicos quando estas atividades não estão associadas à extração.  Esta divisão não compreende o beneficiamento de minerais não-metálicos quando esta atividade está associada à extração (divisão 08) e a fabricação de pedra artificial (p.ex. mármore sintético) (divisão 22).', 'pending_trigger'),
  ('24', 'C', 'METALURGIA', 'Esta divisão compreende a conversão de minérios ferrosos e não-ferrosos em produtos metalúrgicos por meios térmicos, eletrometalúrgicos ou não (fornos, convertedores, etc.), e outras técnicas metalúrgicas de processamento para obtenção de produtos intermediários do processamento de minérios metálicos, tais como gusa, aço líquido, alumina calcinada ou não, mates metalúrgicos de cobre e níquel, etc., a produção de metais em formas primárias ou semi-acabados (lingotes, placas, tarugos, biletes, palanquilhas, etc.), a produção de laminados, relaminados, trefilados, retrefilados (chapas, bobinas, barras, perfis, trilhos, vergalhões, fio-máquina, etc.) e a produção de canos e tubos.  Esta divisão compreende também a produção de peças fundidas de metais ferrosos e não-ferrosos e a produção de barras forjadas de aço (laminados longos).  Esta divisão não compreende a produção de peças forjadas de metais ferrosos e não-ferrosos (divisão 28).', 'pending_trigger'),
  ('25', 'C', 'FABRICAÇÃO DE PRODUTOS DE METAL, EXCETO MÁQUINAS  E EQUIPAMENTOS', 'Esta divisão compreende a fabricação de produtos de metal como estruturas metálicas e obras de caldeiraria pesada para diversas aplicações, caldeiras, tanques e reservatórios metálicos utilizados como instalação para armazenamento e uso industrial e a fabricação de produtos de serralheria, forjaria, estamparia, funilaria, metalurgia de pó, artigos de cutelaria, embalagens metálicas e ferramentas.  Esta divisão compreende também a fabricação de artefatos metálicos para uso doméstico, a fabricação de armas e munições e os serviços de tratamento de metais.  Esta divisão não compreende a manutenção, reparação e instalação realizadas por unidade especializada (divisão 33).', 'pending_trigger'),
  ('26', 'C', 'FABRICAÇÃO DE EQUIPAMENTOS DE INFORMÁTICA, PRODUTOS ELETRÔNICOS E ÓPTICOS', 'Os produtos desta divisão caracterizam-se principalmente pelo uso de circuitos integrados e a aplicação de tecnologias altamente especializadas.  Esta divisão compreende a fabricação de componentes eletrônicos, a fabricação de computadores e periféricos de computadores, a fabricação de equipamentos de comunicação e produtos eletrônicos semelhantes, a fabricação de produtos eletrônicos de consumo, a fabricação de equipamentos de medida, teste, navegação e controle, a fabricação de cronômetros e relógios, a fabricação de equipamentos de irradiação, eletromédicos e eletroterapêuticos e de equipamentos e instrumentos ópticos, fotográficos e cinematográficos.  Esta divisão compreende também a fabricação de mídias magnéticas ou ópticas.', 'pending_trigger'),
  ('27', 'C', 'FABRICAÇÃO DE MÁQUINAS, APARELHOS E MATERIAIS ELÉTRICOS', 'Esta divisão compreende a fabricação de produtos para geração, distribuição e controle de energia elétrica, de aparelhos eletrodomésticos, de equipamentos de iluminação elétrica, sinalização e alarme, de lâmpadas, de fios, cabos e outros materiais elétricos.  Esta divisão compreende também a fabricação de cabos de fibra óptica e de peças para máquinas e equipamentos compreendidos nesta divisão.  Esta divisão não compreende a fabricação de peças e material elétrico e eletrônico para veículos automotores (divisão 29) e a manutenção, reparação e instalação de máquinas e equipamentos compreendidos nesta divisão, quando realizadas por unidade especializada (divisão 33).', 'pending_trigger'),
  ('28', 'C', 'FABRICAÇÃO DE MÁQUINAS E EQUIPAMENTOS', 'Esta divisão compreende a fabricação de máquinas e equipamentos, inclusive os componentes mecânicos, partes e peças, para as atividades industriais, agrícolas, extração mineral e construção, transporte e elevação de cargas e pessoas, para ventilação, refrigeração, instalações térmicas ou outras atividades semelhantes.  Esta divisão distingue a fabricação de máquinas para uso geral (grupo 28.2), que são as usadas por uma grande variedade de indústrias, no comércio e nos serviços e as máquinas de uso específico (grupo 28.6), cujo uso é exclusivo em indústrias ou em grupamento de indústrias da CNAE.  Esta divisão compreende também a fabricação de ferramentas elétricas, a fabricação de peças para máquinas e equipamentos produzidos nesta divisão e a instalação, manutenção e reparação de máquinas e equipamentos produzidos nesta divisão, quando realizadas pela unidade fabricante.  Esta divisão não compreende a instalação, manutenção e reparação de máquinas e equipamentos compreendidos nesta divisão, quando executadas por unidade especializada (divisão 33); a instalação, manutenção e reparação de elevadores e escadas rolantes, quando realizadas por unidade especializada (divisão 43); a instalação de ar refrigerado central (divisão 43); a instalação, reparação e manutenção de ar-condicionado para veículos (divisão 45) e a reparação e manutenção de aparelhos de ar condicionado domésticos (divisão 95).', 'pending_trigger'),
  ('30', 'C', 'FABRICAÇÃO DE OUTROS EQUIPAMENTOS DE TRANSPORTE, EXCETO VEÍCULOS AUTOMOTORES', 'Esta divisão compreende a construção de embarcações e estruturas flutuantes, a fabricação de veículos ferroviários, a fabricação de aeronaves, a fabricação de motocicletas, bicicletas e outros equipamentos de transporte.  Esta divisão compreende também a fabricação de veículos militares de combate, a fabricação de cadeiras de rodas e veículos semelhantes para deficientes físicos, a fabricação de peças e acessórios para os veículos produzidos nesta divisão.  Esta divisão não compreende a manutenção e reparação de embarcações, de veículos ferroviários e de aeronaves (divisão 33); a manutenção de motocicletas (divisão 45) e a reparação de bicicletas (divisão 95).', 'pending_trigger'),
  ('31', 'C', 'FABRICAÇÃO DE MÓVEIS', 'Esta divisão compreende a fabricação de artigos do mobiliário de qualquer material para qualquer uso.  Esta divisão compreende também a fabricação de gabinetes para máquinas de costura, televisores e semelhantes.  Esta divisão não compreende a fabricação de móveis de concreto, cerâmica e pedra (divisão 23); a fabricação de bancos e estofados para veículos automotores (divisão 29), veículos ferroviários e aeronaves (divisão 30) e a reparação de móveis (divisão 95).', 'pending_trigger'),
  ('32', 'C', 'FABRICAÇÃO DE PRODUTOS DIVERSOS', 'Esta divisão compreende a fabricação de uma variedade de bens não incluídos em outras divisões da classificação. Considerando ser esta uma categoria residual da indústria de transformação o processo de produção dos bens e os critérios para agrupamento de classes e divisões não foram aplicados nesta divisão.  Esta divisão compreende a lapidação de gemas (pedras preciosas e semipreciosas) e a fabricação de artefatos de joalheria, bijuteria e semelhantes, a fabricação de instrumentos musicais, a fabricação de artefatos para pesca e esporte, a fabricação de brinquedos, a fabricação de instrumentos não-eletrônicos e materiais para usos em medicina e odontologia, a fabricação de artigos ópticos (óculos, lentes oftálmicas, etc.), a fabricação de acessórios para segurança pessoal e profissional, a fabricação de placas e letreiros e de painéis luminosos e de outros bens não mencionados anteriormente.', 'pending_trigger'),
  ('33', 'C', 'MANUTENÇÃO, REPARAÇÃO E INSTALAÇÃO DE MÁQUINAS E EQUIPAMENTOS', 'Esta divisão compreende as atividades de manutenção, reparação e instalação de máquinas e equipamentos utilizados no processo de produção industrial, realizadas por unidades especializadas, normalmente sob contrato.  A manutenção e reparação de produtos utilizados tanto como bens de capital quanto como bens de consumo são classificadas como reparação de artefatos domésticos (p.ex. a reparação de móveis de escritório e doméstico é classificada na divisão 95).  Esta divisão não compreende a manutenção e reparação de equipamentos de comunicação e computadores e periféricos (divisão 95) e a reparação de artefatos domésticos (divisão 95). A instalação, manutenção e reparação das máquinas e equipamentos quando realizadas pela unidade fabricante, são classificadas nas mesmas classes da fabricação (exceto elevadores, escadas e esteiras rolantes: divisão 43)', 'pending_trigger'),
  ('35', 'D', 'ELETRICIDADE, GÁS E OUTRAS UTILIDADES', '', 'pending_trigger'),
  ('36', 'E', 'CAPTAÇÃO, TRATAMENTO E DISTRIBUIÇÃO DE ÁGUA', 'Esta divisão compreende a captação, tratamento e distribuição de água para atender às necessidades domésticas, comerciais, públicas, industriais e rurais.  Esta divisão compreende também as unidades que operam simultaneamente as atividades de captação, tratamento e distribuição de água e a operação de redes de coleta e tratamento de esgotos.  A operação de canais de irrigação também está incluída nesta divisão; entretanto, o fornecimento de serviços de irrigação por meio de irrigadores e serviços semelhantes de apoio à agricultura não está compreendido nesta divisão (seção A - divisão 01).', 'pending_trigger'),
  ('37', 'E', 'ESGOTO E ATIVIDADES RELACIONADAS', 'Esta divisão compreende as atividades de operação de sistemas de esgoto sanitário, isto é, a gestão das redes, a operação das estações de tratamento de esgoto (ETE) e atividades relacionadas.', 'pending_trigger'),
  ('38', 'E', 'COLETA, TRATAMENTO E DISPOSIÇÃO DE RESÍDUOS; RECUPERAÇÃO DE MATERIAIS', 'Esta divisão compreende a coleta, tratamento e disposição de resíduos e a operação de estações de recuperação de materiais descartados  Esta divisão não compreende a fabricação de produtos novos a partir de matérias-primas secundárias, classificada de acordo com os produtos fabricados (seção C); a revenda de sucatas e resíduos sem qualquer tipo de tratamento (seção G - divisão 46) e o comércio de artigos resultantes de demolição (seção G - divisão 47)', 'pending_trigger'),
  ('39', 'E', 'DESCONTAMINAÇÃO E OUTROS SERVIÇOS DE GESTÃO DE RESÍDUOS', '', 'pending_trigger'),
  ('41', 'F', 'CONSTRUÇÃO DE EDIFÍCIOS', 'Esta divisão compreende a construção de edifícios de todos os tipos (residenciais, comerciais, industriais, agropecuários e públicos), as reformas, manutenções correntes, complementações e alterações de imóveis, a montagem de estruturas de casas, abrigos e edifícios pré-fabricadas in loco para fins diversos de natureza permanente ou temporária quando não realizadas pelo próprio fabricante.  Esta divisão compreende também a realização de empreendimentos imobiliários, residenciais ou não, provendo recursos financeiros, técnicos e materiais para a sua execução e posterior venda (incorporação imobiliária). A execução de obras por empreitada ou subempreitada  Esta divisão não compreende as obras de infra-estrutura (divisão 42) e os serviços especializados em parte do processo de construção (divisão 43).', 'pending_trigger'),
  ('42', 'F', 'OBRAS DE INFRA-ESTRUTURA', 'Esta divisão compreende as obras de infra-estrutura (auto-estradas, vias urbanas, pontes, túneis, ferrovias, metrôs, pistas de aeroportos, portos e projetos de abastecimento de água, sistemas de irrigação, sistemas de esgoto, instalações industriais, redes de transporte por dutos (gasodutos, minerodutos, oleodutos) e linhas de eletricidade, instalações esportivas, etc.), as reformas, manutenções correntes, complementações e alterações de obras de infra-estrutura e a construção de estruturas pré-fabricadas in loco para fins diversos, de natureza permanente ou temporária, exceto edifícios. A execução de obras por empreitada ou subempreitada  Esta divisão não compreende a construção de edifícios (divisão 41), os serviços especializados para a construção, apenas como parte do processo de construção (divisão 43) e os serviços de paisagismo (divisão 81).', 'pending_trigger'),
  ('52', 'H', 'ARMAZENAMENTO E ATIVIDADES AUXILIARES DOS TRANSPORTES', 'Esta divisão compreende as atividades relacionadas com a movimentação e o armazenamento de cargas, antes ou depois de seu transporte, ou entre segmentos de transporte de distintas modalidades, as atividades auxiliares das diversas modalidades de transporte envolvendo a operação da infra-estrutura de suporte nas rodovias, ferrovias, aeroportos, portos, pontes túneis, etc. e as atividades de agenciamento de transporte.  Esta divisão compreende também as atividades relacionadas à organização do transporte de carga.', 'pending_trigger'),
  ('53', 'H', 'CORREIO E OUTRAS ATIVIDADES DE ENTREGA', 'Esta divisão compreende as atividades do Correio Nacional, dos courriers e as atividades de malote e entrega.', 'pending_trigger'),
  ('55', 'I', 'ALOJAMENTO', '', 'pending_trigger'),
  ('56', 'I', 'ALIMENTAÇÃO', '', 'pending_trigger'),
  ('43', 'F', 'SERVIÇOS ESPECIALIZADOS PARA CONSTRUÇÃO', 'Esta divisão compreende a execução de partes de edifícios ou obras de infra-estrutura, tais como: a preparação do terreno para construção, a instalação de materiais e equipamentos necessários ao funcionamento do imóvel e as obras de acabamento.  Em geral, as unidades classificadas nesta divisão são especializadas em um determinado tipo de serviço para a construção civil, comum a diferentes tipos de estruturas e que requer a utilização de técnicas e equipamentos especiais para a sua execução. Como exemplo, podem-se citar as seguintes atividades: as fundações, a concretagem de estruturas, a colocação de revestimentos de qualquer material em paredes e pisos, a instalação de andaimes, a construção de coberturas, etc.  Também está compreendida nesta divisão a construção de estruturas de aço, sempre que esta atividade não seja realizada pelo próprio fabricante das partes metálicas da estrutura (vigas, colunas, lajes, etc.). Os serviços especializados para construção civil são geralmente realizados por subcontratação pela empresa responsável pela realização da construção e, no caso de obras de reforma, normalmente esses serviços são executados diretamente para o proprietário.  Esta divisão compreende também as obras de instalações prediais que permitem o funcionamento e a operação do edifício. Normalmente estas atividades são realizadas conjuntamente à fase de construção, sendo que algumas partes desses serviços podem ser concluídas em um período pré-fixado. Estas atividades incluem as instalações hidráulicas, as instalações de sistemas de calefação e de ar condicionado, antenas, sistemas de alarme e outras instalações elétricas, sistemas de irrigação automáticos, elevadores e escadas rolantes, etc. Também estão incluídos os serviços de tratamento térmico e acústico, alvenaria, refrigeração comercial, a instalação de sistemas de iluminação e de sinalização luminosa e iluminação de rodovias, ferrovias, aeroportos, portos, etc.  Esta divisão não compreende a construção de edifícios (divisão 41), as obras de infra-estrutura (divisão 42), a retirada de entulho (divisão 38) e os serviços de paisagismo (divisão 81).', 'pending_trigger'),
  ('45', 'G', 'COMÉRCIO E REPARAÇÃO DE VEÍCULOS AUTOMOTORES E MOTOCICLETAS', 'Esta divisão compreende a venda por atacado e a varejo de veículos automotores e motocicletas novos e usados e de peças e acessórios para esses veículos, inclui também as atividades de manutenção e reparação de veículos automotores e motocicletas  Esta divisão compreende também as atividades de representantes comerciais e agentes do comércio, por atacado e a varejo de veículos automotores e motocicletas e as vendas sob consignação desses produtos  Esta divisão não compreende a locação de veículos sem motorista ou condutor (divisão 77) e com motorista ou condutor (divisão 49), a venda de combustíveis e lubrificantes para veículos automotores por atacado (grupo 46.8) e varejo (grupo 47.3)', 'pending_trigger'),
  ('60', 'J', 'ATIVIDADES DE RÁDIO E DE TELEVISÃO', 'Esta divisão compreende as atividades de criação de conteúdo e de aquisição dos direitos de distribuição e posterior difusão desse conteúdo em rádio e televisão. Compreende também a emissão de dados integrada à difusão por rádio e televisão. Essa difusão pode usar diferentes tecnologias de transmissão: por microondas, cabo, satélite ou internet.  Esta divisão compreende também a produção pelas programadoras de televisão por assinatura, de programas que têm um formato limitado ou especializado, como os programas de notícias, esportes, educação, etc., que são transmitidos pelas operadoras de televisão por assinatura mediante subscrição.  Esta divisão não compreende a transmissão das operadoras de televisão por assinatura (grupo 61.4).', 'pending_trigger'),
  ('46', 'G', 'COMÉRCIO POR ATACADO, EXCETO VEÍCULOS AUTOMOTORES E MOTOCICLETAS', 'Esta divisão compreende as atividades de venda por atacado de mercadorias, exceto de veículos automotores e motocicletas, quer realizada por comerciante atacadista ou por representante ou agente do comércio. Em geral, esta venda é uma etapa intermediária da distribuição de mercadorias; e está organizada para vender mercadorias em grandes quantidades a varejistas, a empresas, estabelecimentos agropecuários, cooperativas e a uma clientela institucional. Entretanto, alguns atacadistas, sobretudo os que fornecem bens de capital de grande porte, vendem mercadorias por unidade aos usuários finais   As atividades dos representantes e agentes do comércio que, sob contrato, comercializam a mercadoria em nome de terceiros ou fazem a intermediação entre vendedores e compradores de mercadorias no atacado, são compreendidas no grupo 46.1 e as atividades dos atacadistas que compram as mercadorias que revendem são tratadas nos grupos 46.2, 46.3, 46.4, 46.5, 46.6, 46.7, 46.8 e 46.9.  Esta divisão compreende também as manipulações habituais do comércio atacadista - montagem, classificação e agrupamento de produtos em grande escala, fracionamento, acondicionamento e envasamento, redistribuição em recipientes de menor escala - quando realizadas por conta própria e as atividades de representantes comerciais e agentes do comércio atacadista realizadas via internet  Esta divisão não compreende o comércio de veículos automotores e motocicletas, peças e acessórios (divisão 45); o aluguel de máquinas e equipamentos sem operadores, de objetos pessoais e utilidades domésticas (divisão 77) e as atividades de fracionamento, acondicionamento e envasamento sob contrato (8292-0/00)', 'pending_trigger'),
  ('47', 'G', 'COMÉRCIO VAREJISTA', 'Esta divisão compreende as atividades de revenda (venda sem transformação significativa) de bens de consumo novos e usados para o público em geral, preponderantemente para o consumidor final. O comércio varejista é organizado para vender mercadorias em pequenas quantidades ao consumidor final, representando, portanto, o último elo da cadeia de distribuição.  Inclui tanto o comércio tradicional em lojas abertas ao público como o varejo por meios não tradicionais por catálogo, porta-a-porta, televisão, internet, etc.  Esta divisão compreende também as unidades comerciais abertas ao?público, em lojas com exposição de mercadorias, de produtos tais como computadores pessoais, artigos de papelaria, tintas ou madeira, ainda que parte das vendas realizadas não seja para uso pessoal ou doméstico.  A classificação das atividades do comércio varejista baseia-se na gama de produtos vendidos, sem distinção da forma de comercialização em loja ou fora de loja (por correio, catálogo, porta-a-porta, internet, etc.) e apóia-se em conceitos e convenções relativos a especialização e predominância  Especialização:  A especialidade é definida em função da gama de produtos vendidos, tomando como referência o conteúdo das classes discriminadas nos grupos 47.2, 47.5, 47.6, 47.7 e 47.8. Se os produtos contidos numa destas classes representam mais de 50% das vendas, trata-se de comércio especializado nesta classe. Caso contrário, é preciso levar em conta a gama de produtos que representam mais de 5% do faturamento (ou de qualquer outra variável que o substitua). Com quatro classes ou menos, o comércio é especializado, sendo classificado na classe com maior peso. Com vendas distribuídas em mais de quatro classes, o comércio é não-especializado (grupo 47.1).  Se a unidade produtiva é um comércio-especializado, se classificará em algum dos grupos 47.2, 47.5, 47.6, 47.7 e 47.8 considerando para isso as regras definidas pelo método descendente (do nível mais agregado para os menos agregados).  Se, pelo contrário, a unidade compreende uma gama de produtos igual ou superior a cinco, trata-se de comércio não-especializado e se classificará no grupo 47.1.  Predominância:  A predominância é definida, nas unidades não-especializadas, em função da participação da venda de alimentos, bebidas e fumo no faturamento total. Quando esta participação for de 35% ou mais, trata-se de comércio não-especializado com predominância alimentar. Neste caso, esta unidade se classificará em uma das seguintes classes: 47.11-3 ou 47.12-1.  Caso não ocorra esta situação, trata-se de comércio não-especializado com predominância não-alimentar, compreendido na classe 47.13-0.  Além da venda de mercadorias, há casos de comerciantes varejistas que prestam serviços pós-venda, tais como serviços de entrega, montagem e instalação. Como regra geral, os estabelecimentos que revendem mercadorias no varejo e que têm serviços pós-vendas são classificados nesta divisão.  Esta divisão compreende também as atividades usualmente associadas ao comércio, tais como: a classificação, fracionamento e acondicionamento quando realizadas na unidade comercial; a venda a varejo realizada por agentes comissionados e sob consignação (classificados nas classes dos produtos correspondentes) e a venda à varejo de combustíveis e lubrificantes para veículos automotores e motocicletas, e barcos de pequeno porte.  Esta divisão não compreende a venda de veículos automotores, motocicletas e componentes (divisão 45); a venda de bens destinados a usuários industriais (divisão 46); a venda de alimentos e bebidas para consumo no local (divisão 56); o aluguel de artigos de uso pessoal e doméstico (divisão 77).', 'pending_trigger'),
  ('49', 'H', 'TRANSPORTE TERRESTRE', 'Esta divisão compreende o transporte de passageiros e carga por rodovias e ferrovias e dutos.  Esta divisão compreende também o transporte rodoviário sob regime de fretamento e o transporte em trens turísticos, teleféricos e similares.', 'pending_trigger'),
  ('50', 'H', 'TRANSPORTE AQUAVIÁRIO', 'Esta divisão compreende o transporte aquaviário de pessoas e mercadorias 	 Esta divisão compreende também a operação de embarcações para fins turísticos; o fretamento de embarcações com tripulação; e a operação de embarcações para apoio marítimo e portuário  Esta divisão não compreende as atividades auxiliares ao transporte aquaviário, tais como a administração de portos, operação de terminais, agenciamento marítimo, etc. (divisão 52); e as atividades de restaurantes e bares em embarcações exploradas sob contrato (divisão 56)', 'pending_trigger'),
  ('51', 'H', 'TRANSPORTE AÉREO', 'Esta divisão compreende o transporte aéreo de passageiros e carga, em linhas regulares ou não.  Esta divisão compreende também o transporte espacial.  Esta divisão não compreende a gestão de aeroportos (divisão 52); as atividades de manutenção e reparação de aeronaves e seus motores (divisão 33); as atividades de manutenção de aeronaves na pista (divisão 33); as atividades de pulverizações aéreas (divisão 01); publicidade aérea (divisão 73); fotografias aéreas (divisão 74)', 'pending_trigger'),
  ('71', 'M', 'SERVIÇOS DE ARQUITETURA E ENGENHARIA; TESTES E ANÁLISES TÉCNICAS', 'Esta divisão compreende a prestação de serviços de arquitetura, de engenharia e outras atividades técnicas relacionadas à arquitetura e engenharia, tais como as atividades de: cartografia, topografia, geodésia, geologia, etc.  Esta divisão compreende também as atividades de realização de testes e análises técnicas em todos os tipos de materiais e de produtos.', 'pending_trigger'),
  ('58', 'J', 'EDIÇÃO E EDIÇÃO INTEGRADA À IMPRESSÃO', 'Esta divisão compreende as atividades de edição e de edição integrada à impressão de livros, jornais, revistas, periódicos, dicionários, enciclopédias, atlas, mapas, listas, cadastros e outras publicações. Estas atividades incluem a aquisição de direitos autorais para a edição e disseminação de produtos com conteúdo de informação, ou seja, para a reprodução e a distribuição desse conteúdo. Estão incluídas nesta divisão todas as formas de edição de produtos com conteúdo de informação (impressa, eletrônica ou sonora, na internet e em produtos multimídia, como CDs), exceto a edição de programas informáticos (software).  Esta divisão compreende também a atividade de edição on-line (na internet), quando desenvolvida adicionalmente à edição impressa.  Esta divisão não compreende as atividades de edição de filmes cinematográficos, filmes em fitas de vídeo, em DVDs ou em outras mídias, a produção de matrizes originais para gravação de som (divisão 59), as atividades de impressão sob contrato e a reprodução de matrizes originais de som (divisão 18).', 'pending_trigger'),
  ('59', 'J', 'ATIVIDADES CINEMATOGRÁFICAS, PRODUÇÃO DE VÍDEOS E DE PROGRAMAS DE TELEVISÃO; GRAVAÇÃO DE SOM E EDIÇÃO DE MÚSICA', 'Esta divisão compreende a produção de filmes em películas, fitas de vídeo, DVDs ou em outros suportes para qualquer finalidade; as atividades de apoio, como edição, dublagem, colocação de legendas, etc.; a distribuição e licenciamento de filmes cinematográficos e de outros filmes para as empresas distribuidoras e exibidoras; a exibição de filmes.  Esta divisão compreende também a compra e a venda de direitos autorais de filmes cinematográficos e de outros filmes, bem como os direitos de distribuição dessa produção.  Esta divisão não compreende o comércio atacadista de fitas de vídeo e DVDs gravados (grupo 46.4) e o aluguel de fitas de vídeo, DVDs e similares (grupo 77.2).', 'pending_trigger'),
  ('61', 'J', 'TELECOMUNICAÇÕES', 'Esta divisão compreende as atividades de prestação de serviços de telecomunicações e serviços conexos, isto é, as atividades de transmissão, emissão ou recepção de símbolos, caracteres, sinais, escritos, imagens, sons ou informações de qualquer natureza.   A infra-estrutura de telecomunicações que dá suporte a estas atividades pode ser baseada em uma única tecnologia ou em uma combinação de tecnologias (por fio, por microondas e por satélite).  A principal característica das atividades classificadas nesta divisão é a transmissão de conteúdo, sem envolver as atividades de criação. O detalhamento das categorias pertencentes a esta divisão foi baseado no tipo de infra-estrutura preponderante.  As atividades das operadoras de televisão foram destacadas para dar maior visibilidade a este segmento. Estas atividades incluem a transmissão e distribuição da programação dos canais de televisão por assinatura.', 'pending_trigger'),
  ('62', 'J', 'ATIVIDADES DOS SERVIÇOS DE TECNOLOGIA DA INFORMAÇÃO', '', 'pending_trigger'),
  ('63', 'J', 'ATIVIDADES DE PRESTAÇÃO DE SERVIÇOS DE INFORMAÇÃO', 'Esta divisão compreende as atividades dos portais de busca na internet, as atividades de tratamento e hospedagem de dados na internet e as demais atividades com a finalidade de permitir o acesso a serviços de informação.', 'pending_trigger'),
  ('64', 'K', 'ATIVIDADES DE SERVIÇOS FINANCEIROS', 'Esta divisão compreende as atividades com a finalidade de criar, coletar, intermediar e redistribuir recursos financeiros próprios ou de terceiros sob sua responsabilidade.  Esta divisão compreende também as atividades das sociedades de capitalização.  Esta divisão não compreende as atividades de seguros, resseguros, previdência complementar e planos de saúde (divisão 65) e as atividades auxiliares dos serviços financeiros, seguros, previdência complementar e planos de saúde (divisão 66).', 'pending_trigger'),
  ('65', 'K', 'SEGUROS, RESSEGUROS, PREVIDÊNCIA COMPLEMENTAR E PLANOS DE SAÚDE', 'Esta divisão compreende as atividades de criação de fundos para todos os tipos de seguros (vida e não-vida), resseguros e de fundos privados para aposentadoria (previdência complementar). Em todos os casos, envolvem a coleta e a aplicação dos fundos. As atividades de seguros, resseguros, previdência complementar e planos de saúde incluem planos de cobertura de risco de curto e longo prazos, com ou sem componentes de poupança. A atividade de seguros consiste na assunção e gestão de riscos pelas empresas de seguros, com os riscos e condições de aceitação especificados em um contrato (apólice de seguros). As atividades de seguros, previdência complementar e planos de saúde têm como pressuposto a transformação de riscos individuais em riscos coletivos.  Esta divisão compreende também os planos de saúde fora do âmbito das seguradoras.  Esta divisão não compreende a seguridade social obrigatória (84.30-2) e as atividades das sociedades de capitalização (64.50-6).', 'pending_trigger'),
  ('66', 'K', 'ATIVIDADES AUXILIARES DOS SERVIÇOS FINANCEIROS, SEGUROS, PREVIDÊNCIA COMPLEMENTAR E PLANOS DE SAÚDE', 'Esta divisão compreende as atividades vinculadas aos serviços financeiros, seguros, previdência complementar e planos de saúde, sem que se constituam por si mesmas algum desses serviços.', 'pending_trigger'),
  ('68', 'L', 'ATIVIDADES IMOBILIÁRIAS', '', 'pending_trigger'),
  ('69', 'M', 'ATIVIDADES JURÍDICAS, DE CONTABILIDADE E DE AUDITORIA', 'Esta divisão compreende a representação legal dos interesses de uma parte contra outra diante dos tribunais ou de outros órgãos judiciais, realizada por advogados ou sob sua supervisão, tais como: aconselhamento e representação em ações civis, aconselhamento e representação em ações criminais, aconselhamento e representação em ações administrativas, trabalhistas e comerciais.  Esta divisão compreende as atividades de preparo de documentos jurídicos como estatutos sociais, escrituras de constituição, contratos de sociedade coletiva ou documentos similares para formação de sociedades, concessão de patentes e registro de marcas, de desenhos industriais, contratos de transferência de tecnologia, de indicações geográficas e de programas de computador, bem como, outras atividades auxiliares da justiça como as de arbitragem, de mediação, perícia, etc.  Esta divisão compreende também as atividades de contabilidade e auditoria contábil, de guarda-livros, de planejamento de sistemas contábeis, de preparo de balanços e a atividade de registro de domínio de endereço de internet.', 'pending_trigger'),
  ('70', 'M', 'ATIVIDADES DE SEDES DE EMPRESAS E DE CONSULTORIA EM GESTÃO EMPRESARIAL', '', 'pending_trigger'),
  ('72', 'M', 'PESQUISA E DESENVOLVIMENTO CIENTÍFICO', 'Esta divisão compreende três tipos de atividades de pesquisa e desenvolvimento: as atividades de pesquisas básicas, de trabalhos experimentais ou teóricos, desenvolvidos com o objetivo de obtenção de novos conhecimentos sobre causas de fenômenos ou efeitos observáveis, sem a previsão de aplicação ou de uso determinado; as atividades de pesquisa aplicada, de investigação original, que têm por objetivo a aquisição de novos conhecimentos direcionados, principalmente, para um objetivo ou finalidade específicos; e as atividades de pesquisa experimental, de trabalho sistemático baseado em conhecimentos prévios, envolvendo pesquisas ou experiências com o objetivo de criar ou aperfeiçoar materiais, produtos, dispositivos, processos, sistemas e serviços.  Esta divisão não compreende a educação superior, ainda que contenha atividades de pesquisa e desenvolvimento (grupo 85.3), a pesquisa de mercado (grupo 73.2) e a gestão de recursos e financiamento das atividades de pesquisas pelo poder público (grupo 84.1).', 'pending_trigger'),
  ('73', 'M', 'PUBLICIDADE E PESQUISA DE MERCADO', 'Esta divisão compreende a criação, produção e realização de campanhas publicitárias e a sua veiculação em jornais, revistas, rádio, televisão e em outros veículos de comunicação.  Esta divisão compreende também a realização de pesquisas de mercado e de opinião, visando a mensurar o potencial do mercado, conhecer hábitos de compra dos consumidores e conhecer a opinião da população sobre questões variadas.', 'pending_trigger'),
  ('74', 'M', 'OUTRAS ATIVIDADES PROFISSIONAIS, CIENTÍFICAS E TÉCNICAS', 'Esta divisão compreende as atividades de serviços profissionais, científicos e técnicos, exceto as atividades jurídicas, de contabilidade e auditoria, de engenharia e de arquitetura.  Esta divisão não compreende as atividades de realização de testes e análises técnicas, de consultoria em gestão empresarial, de pesquisa e desenvolvimento científico e as atividades de publicidade e de pesquisa de mercado e de opinião.', 'pending_trigger'),
  ('75', 'M', 'ATIVIDADES VETERINÁRIAS', '', 'pending_trigger'),
  ('91', 'R', 'ATIVIDADES LIGADAS AO PATRIMÔNIO CULTURAL E AMBIENTAL', 'Esta divisão compreende as atividades de bibliotecas e arquivos; as atividades de museus de todos os tipos, jardins botânicos e zoológicos, parques nacionais, reservas ecológicas e áreas de proteção ambiental.  Esta divisão compreende também as atividades de exploração, restauração artística e conservação de lugares e prédios históricos e de outros locais de interesse cultural ou educacional.', 'pending_trigger'),
  ('92', 'R', 'ATIVIDADES DE EXPLORAÇÃO DE JOGOS DE AZAR E APOSTAS', 'Esta divisão compreende a operação de casas de jogos e apostas, tais como: cassinos, bingos, terminais de videogames, fliperamas, etc.', 'pending_trigger'),
  ('77', 'N', 'ALUGUÉIS NÃO-IMOBILIÁRIOS E GESTÃO DE ATIVOS INTANGÍVEIS NÃO-FINANCEIROS', 'Esta divisão compreende as atividades de aluguel e de leasing operacional de bens tangíveis, realizadas por um período de curta ou de longa duração, tais como: automóveis, computadores, bens de consumo, máquinas e equipamentos industriais. Somente o leasing operacional está incluído nesta divisão.  Esta divisão compreende também as atividades de cessão ou direito de uso de ativos intangíveis não-financeiros, tais como patentes, marcas, acordos de franquias, cuja remuneração pode ser feita por comissão, pagamento de royalties, etc.  Esta divisão está subdividida nas seguintes atividades: locação e leasing operacional de meios de transporte sem condutor, aluguel de objetos pessoais e domésticos, aluguel e leasing operacional de máquinas e equipamentos sem operador e gestão de ativos intangíveis não-financeiros.  Esta divisão não compreende o arrendamento mercantil ou leasing financeiro (divisão 64), o aluguel de imóveis (divisão 68) e os serviços de aluguel de máquinas e equipamentos com pessoal de operação, que são considerados prestação de serviços contratados e como tal são classificados na atividade onde são exercidos, tais como: o aluguel de equipamentos de construção e demolição com operador, que é classificado junto à atividade específica de construção que inclui o uso destes equipamentos (seção F); a locação de automóveis com motorista (49.29-9); a locação de caminhões com motorista (grupo 49.3); o fretamento de embarcações com tripulação (divisão 50) e o fretamento de aeronaves com tripulação (divisão 51).', 'pending_trigger'),
  ('78', 'N', 'SELEÇÃO, AGENCIAMENTO E LOCAÇÃO DE MÃO-DE-OBRA', 'Esta divisão compreende as atividades de seleção e agenciamento de mão-de-obra que implicam o recrutamento e encaminhamento de candidatos a empregos em empresas clientes, sendo que os indivíduos selecionados não são funcionários das agências de emprego. Estão incluídas as atividades de seleção e colocação de executivos em empresas clientes e as atividades de agenciamento de elenco (casting).  Esta divisão compreende também as atividades de locação de mão-de-obra temporária. Os trabalhadores temporários são encaminhados às empresas clientes para complementar o seu quadro de pessoal por tempo determinado e são remunerados pelas agências de trabalho temporário nas condições da legislação trabalhista, porém a supervisão desse pessoal é feita pelo cliente. Estão também compreendidas nesta divisão as atividades de fornecimento de recursos humanos e de serviços de gestão de recursos humanos a empresas clientes.', 'pending_trigger'),
  ('79', 'N', 'AGÊNCIAS DE VIAGENS, OPERADORES TURÍSTICOS E SERVIÇOS DE RESERVAS', 'Esta divisão compreende a atividade de agências voltadas, principalmente, à venda de viagens, de pacotes turísticos, de serviços de transporte e de alojamento, ao público em geral e a clientes comerciais.  Esta divisão compreende também as atividades de organização de excursões que são vendidas em agências de viagem ou diretamente por agentes e operadores turísticos e outras atividades de serviços relacionados a viagens, inclusive serviços de reservas e de guias turísticos.', 'pending_trigger'),
  ('80', 'N', 'ATIVIDADES DE VIGILÂNCIA, SEGURANÇA E INVESTIGAÇÃO', 'Esta divisão compreende os serviços relacionados à segurança, tais como: serviços de vigilância e de investigação; serviços de transporte de valores; a operação de sistemas de alarmes de segurança, inclusive alarmes de incêndio, quando realizada por monitoramento remoto, o que geralmente envolve também a venda, instalação e manutenção desses sistemas. A venda, instalação e manutenção de sistemas de alarme, quando oferecidas separadamente dos serviços de monitoramento, não fazem parte desta divisão e são classificadas em comércio varejista, construção, etc.', 'pending_trigger'),
  ('81', 'N', 'SERVIÇOS PARA EDIFÍCIOS E ATIVIDADES PAISAGÍSTICAS', 'Esta divisão compreende o fornecimento de mão-de-obra para a prestação de uma série de serviços de apoio em instalações prediais de clientes. As unidades aqui classificadas fornecem pessoal para desenvolver as atividades de apoio mas não estão envolvidas ou têm responsabilidade com o desenvolvimento da atividade empresarial do cliente.  Esta divisão compreende também as atividades de limpeza interior e exterior de edifícios de todos os tipos, limpeza de máquinas industriais, de trens, ônibus, etc.; a limpeza no interior de caminhões, tanques marítimos; os serviços de imunização e controle de pragas urbanas, em edifícios, navios, trens, etc.; a limpeza de garrafas, a limpeza de ruas; as atividades de execução e manutenção de jardins e gramados. Estão compreendidas nesta divisão as atividades paisagísticas e os condomínios prediais.', 'pending_trigger'),
  ('82', 'N', 'SERVIÇOS DE ESCRITÓRIO, DE APOIO ADMINISTRATIVO E OUTROS SERVIÇOS PRESTADOS PRINCIPALMENTE ÀS EMPRESAS', 'Esta divisão compreende o fornecimento de um conjunto de serviços combinados, administrativos e de escritório de rotina, principalmente às empresas. Compreende também serviços de apoio às atividades de rotina das empresas, prestados por terceiros, sob contrato Esta divisão compreende também todas as atividades de apoio a empresas não classificadas anteriormente. As unidades classificadas nesta divisão não fornecem equipe operacional para desenvolver todas as operações de uma empresa.', 'pending_trigger'),
  ('84', 'O', 'ADMINISTRAÇÃO PÚBLICA, DEFESA E SEGURIDADE SOCIAL', '', 'pending_trigger'),
  ('85', 'P', 'EDUCAÇÃO', '', 'pending_trigger'),
  ('86', 'Q', 'ATIVIDADES DE ATENÇÃO À SAÚDE HUMANA', 'Esta divisão compreende as atividades de hospitais gerais ou especializados que permitem internações de longa ou curta duração, hospitais psiquiátricos, centros de medicina preventiva, consultórios médicos e dentários, clínicas médicas e outras atividades ambulatoriais. Os locais onde são prestadas essas atividades possuem infra-estrutura para internação e realização de cirurgias ou para a realização de diagnósticos, procedimentos cirúrgicos e tratamentos médicos.   Esta divisão compreende também as atividades praticadas por todos os profissionais relacionados à área da saúde, as atividades de apoio à gestão de saúde e as de práticas integrativas e complementares à saúde humana.', 'pending_trigger'),
  ('87', 'Q', 'ATIVIDADES DE ATENÇÃO À SAÚDE HUMANA INTEGRADAS COM ASSISTÊNCIA SOCIAL, PRESTADAS EM RESIDÊNCIAS COLETIVAS E PARTICULARES', 'Esta divisão compreende a provisão de serviços residenciais combinados com serviços de enfermagem e assistência social. Na composição destas atividades, a infra-estrutura fornecida é significativa sendo os serviços prestados uma combinação de serviços de saúde e de serviços sociais. Os serviços de saúde compreendem, sobretudo, a prestação de serviços de enfermagem.', 'pending_trigger'),
  ('88', 'Q', 'SERVIÇOS DE ASSISTÊNCIA SOCIAL SEM ALOJAMENTO', 'Esta divisão compreende o fornecimento de uma variedade de serviços de assistência social. As atividades incluídas nesta divisão não fornecem serviços de alojamento, exceto se forem de caráter temporário.', 'pending_trigger'),
  ('90', 'R', 'ATIVIDADES ARTÍSTICAS, CRIATIVAS E DE ESPETÁCULOS', 'Esta divisão compreende a produção e promoção de artes cênicas, espetáculos e atividades complementares. Compreende também as atividades de criação artística, como a de artistas plásticos (pintores, escultores) e escritores, bem como a gestão de espaços para artes cênicas, espetáculos e outras atividades artísticas.', 'pending_trigger'),
  ('93', 'R', 'ATIVIDADES ESPORTIVAS E DE RECREAÇÃO E LAZER', 'Esta divisão compreende as atividades esportivas, recreativas e de lazer, exceto as atividades de bibliotecas, museus, exploração de locais históricos, jardins botânicos e zoológicos e reservas ecológicas compreendidas na divisão 91 e as atividades de exploração de jogos de azar e apostas compreendidas na divisão 92.  Esta divisão não compreende as artes cênicas, a música e outras artes e atividades de entretenimento como os grupos e companhias de teatro, música, dança, etc. (divisão 90).', 'pending_trigger'),
  ('94', 'S', 'ATIVIDADES DE ORGANIZAÇÕES ASSOCIATIVAS', 'Esta divisão compreende as atividades das organizações associativas que representam os interesses de grupos especiais ou que defendem idéias e causas diante da opinião pública. As atividades dessas organizações podem envolver ou beneficiar indivíduos que não pertencem a essas organizações.  As atividades das organizações associativas estão agrupadas de acordo com o tipo de finalidade desenvolvida, tais como: as voltadas para os interesses dos empregadores, de grupos de profissionais, da comunidade científica, dos empregados, de grupos religiosos, políticos, culturais, etc.', 'pending_trigger'),
  ('95', 'S', 'REPARAÇÃO E MANUTENÇÃO DE EQUIPAMENTOS DE INFORMÁTICA E COMUNICAÇÃO E DE OBJETOS PESSOAIS E DOMÉSTICOS', 'Esta divisão compreende as atividades de reparação e manutenção de equipamentos de informática, tais como, desktops, monitores, laptops, terminais de computação, impressoras, etc.  Esta divisão compreende também a reparação e a manutenção de equipamentos de comunicação como fax, rádios transmissores e de aparelhos eletrônicos de uso doméstico como rádios e televisores; também estão incluídos os objetos de uso pessoal como calçados e roupas, móveis, artigos esportivos, instrumentos musicais, etc.  Esta divisão não compreende a reparação de equipamentos médico-hospitalares, instrumentos laboratoriais e aparelhos de radar (divisão 33).', 'pending_trigger'),
  ('96', 'S', 'OUTRAS ATIVIDADES DE SERVIÇOS PESSOAIS', 'Esta divisão compreende todos os serviços não mencionados anteriormente na classificação, tais como os serviços de lavanderias, tinturarias, cabeleireiros, tratamentos de beleza, serviços de funerais e outras atividades relacionadas.', 'pending_trigger'),
  ('97', 'T', 'SERVIÇOS DOMÉSTICOS', '', 'pending_trigger'),
  ('99', 'U', 'ORGANISMOS INTERNACIONAIS E OUTRAS INSTITUIÇÕES EXTRATERRITORIAIS', '', 'pending_trigger')
INSERT INTO qdi.cnae_grupo (grupo_id, divisao_id, descricao, observacoes, hash_conteudo) VALUES
  ('011', '01', 'PRODUÇÃO DE LAVOURAS TEMPORÁRIAS', 'Este grupo compreende o cultivo de plantas de ciclo vegetativo de curta duração, até 1 (um) ano, utilizando técnicas de cultivo tradicional, orgânico, ou ainda o cultivo de plantas modificadas geneticamente.', 'pending_trigger'),
  ('012', '01', 'HORTICULTURA E FLORICULTURA', 'Este grupo compreende o cultivo de produtos hortícolas e de plantas da floricultura - flores, folhagens e plantas ornamentais - para corte, vasos, jardino-cultura, ornamentação ou paisagismo. Os produtos hortícolas são plantas de consistência herbácea com ciclo vegetativo de até 6 (seis) meses, normalmente cultivadas de forma intensiva. As plantas da floricultura têm ciclos vegetativos de curta, média ou de longa duração.  As plantas deste grupo são cultivadas em ambiente natural ou protegido (estufas, casas de vegetação, hidroponia, plasticultura), utilizando técnicas de cultivo tradicional, orgânico, ou ainda o cultivo de plantas modificadas geneticamente.', 'pending_trigger'),
  ('013', '01', 'PRODUÇÃO DE LAVOURAS PERMANENTES', 'Este grupo compreende o cultivo de plantas perenes, isto é, de ciclo vegetativo de longa duração. Essas plantas produzem por vários anos sucessivos sem a necessidade de novos plantios após colheita, sendo utilizadas técnicas de cultivo tradicional, orgânico, assim como o cultivo de plantas modificadas geneticamente.', 'pending_trigger'),
  ('014', '01', 'PRODUÇÃO DE SEMENTES E MUDAS CERTIFICADAS', 'Este grupo compreende a produção de sementes e mudas certificadas.  A produção de sementes e mudas certificadas é realizada por produtores agrícolas especializados a partir de sementes básicas que resultam da multiplicação de sementes genéticas, desenvolvidas em laboratório. A permanência das características obtidas com o melhoramento genético é garantida pela entidade certificadora da semente genética, através de testes em laboratórios de análise de sementes e de plantio em campo.  O melhoramento genético pode ser obtido de forma tradicional, a partir de cruzamento de plantas, ou com o uso de engenharia genética, envolvendo interferência direta no DNA da planta.', 'pending_trigger'),
  ('015', '01', 'PECUÁRIA', 'Este grupo compreende a criação e a produção animal, exceto animais aquáticos.  Neste grupo as classes de atividades são organizadas segundo a espécie animal.  Este grupo compreende também a criação de animais modificados geneticamente.  Este grupo não compreende o alojamento do gado por curta duração (grupo 01.6).', 'pending_trigger'),
  ('016', '01', 'ATIVIDADES DE APOIO À AGRICULTURA E À PECUÁRIA; ATIVIDADES DE PÓS-COLHEITA', '', 'pending_trigger'),
  ('017', '01', 'CAÇA E SERVIÇOS RELACIONADOS', '', 'pending_trigger'),
  ('021', '02', 'PRODUÇÃO FLORESTAL - FLORESTAS PLANTADAS', '', 'pending_trigger'),
  ('022', '02', 'PRODUÇÃO FLORESTAL - FLORESTAS NATIVAS', '', 'pending_trigger'),
  ('023', '02', 'ATIVIDADES DE APOIO À PRODUÇÃO FLORESTAL', '', 'pending_trigger'),
  ('031', '03', 'PESCA', 'Este grupo compreende a pesca e as atividades direcionadas ao recolhimento de organismos aquáticos vivos, predominantemente peixes, crustáceos e moluscos inclusive plantas de águas oceânicas, costeiras ou de águas interiores, para consumo humano ou para outras finalidades, por meios individualizados ou com o uso de redes, linhas e armadilhas. Tais atividades podem ser conduzidas nas margens das praias (coleta de moluscos, mexilhões e ostras), em regiões costeiras ou em alto mar. Os recursos aquáticos capturados pela atividade da pesca são normalmente de propriedade pública, diferentemente da aqüicultura (grupo 03.2), onde os recursos aquáticos cultivados são de domínio particular.  A pesca compreende também as atividades de prevenção e renovação de cardumes', 'pending_trigger'),
  ('032', '03', 'AQÜICULTURA', 'Este grupo compreende a aqüicultura, isto é, processo de produção que envolve o cultivo de organismos aquáticos (peixes, crustáceos, moluscos, plantas aquáticas, jacarés e anfíbios), fazendo uso de técnicas que intensificam a produtividade dos organismos criados além da capacidade natural de desenvolvimento (por exemplo: alimentação adequada, sanidade do ambiente de criação e dos organismos criados, proteção contra os predadores, etc.). O cultivo consiste na criação do animal ou planta aquática desde a fase inicial do ciclo vital até sua fase juvenil ou adulta, sob as condições exigidas por cada organismo até que detenha as características demandadas no mercado. Os organismos da aqüicultura são de propriedade particular, individual, corporativa ou estatal, diferentemente da pesca (grupo 03.1), onde os recursos aquáticos capturados são de domínio público.', 'pending_trigger'),
  ('050', '05', 'EXTRAÇÃO DE CARVÃO MINERAL', '', 'pending_trigger'),
  ('060', '06', 'EXTRAÇÃO DE PETRÓLEO E GÁS NATURAL', '', 'pending_trigger'),
  ('071', '07', 'EXTRAÇÃO DE MINÉRIO DE FERRO', '', 'pending_trigger'),
  ('072', '07', 'EXTRAÇÃO DE MINERAIS METÁLICOS NÃO-FERROSOS', '', 'pending_trigger'),
  ('081', '08', 'EXTRAÇÃO DE PEDRA, AREIA E ARGILA', '', 'pending_trigger'),
  ('089', '08', 'EXTRAÇÃO DE OUTROS MINERAIS NÃO-METÁLICOS', '', 'pending_trigger'),
  ('091', '09', 'ATIVIDADES DE APOIO À EXTRAÇÃO DE PETRÓLEO E GÁS NATURAL', '', 'pending_trigger'),
  ('099', '09', 'ATIVIDADES DE APOIO À EXTRAÇÃO DE MINERAIS, EXCETO PETRÓLEO E GÁS NATURAL', '', 'pending_trigger'),
  ('101', '10', 'ABATE E FABRICAÇÃO DE PRODUTOS DE CARNE', '', 'pending_trigger'),
  ('102', '10', 'PRESERVAÇÃO DO PESCADO E FABRICAÇÃO DE PRODUTOS DO PESCADO', '', 'pending_trigger'),
  ('103', '10', 'FABRICAÇÃO DE CONSERVAS DE FRUTAS, LEGUMES E OUTROS VEGETAIS', '', 'pending_trigger'),
