  ('112', '11', 'FABRICAÇÃO DE BEBIDAS NÃO-ALCOÓLICAS', '', 'pending_trigger'),
  ('121', '12', 'PROCESSAMENTO INDUSTRIAL DO FUMO', '', 'pending_trigger'),
  ('122', '12', 'FABRICAÇÃO DE PRODUTOS DO FUMO', '', 'pending_trigger'),
  ('131', '13', 'PREPARAÇÃO E FIAÇÃO DE FIBRAS TÊXTEIS', '', 'pending_trigger'),
  ('132', '13', 'TECELAGEM, EXCETO MALHA', '', 'pending_trigger'),
  ('133', '13', 'FABRICAÇÃO DE TECIDOS DE MALHA', '', 'pending_trigger'),
  ('134', '13', 'ACABAMENTOS EM FIOS, TECIDOS E ARTEFATOS TÊXTEIS', '', 'pending_trigger'),
  ('135', '13', 'FABRICAÇÃO DE ARTEFATOS TÊXTEIS, EXCETO VESTUÁRIO', 'Este grupo inclui a fabricação de artefatos diversos confeccionados com qualquer material têxtil, inclusive com tecidos de malha.  Inclui também a fabricação de artigos de tapeçaria, cordoaria, a fabricação de tecido-não-tecido (TNT), geotêxteis ou geossintéticos e outros tecidos especiais e seus artefatos, as redes, bordados, artefatos de passamanaria e semelhantes.', 'pending_trigger'),
  ('141', '14', 'CONFECÇÃO DE ARTIGOS DO VESTUÁRIO E ACESSÓRIOS', '', 'pending_trigger'),
  ('142', '14', 'FABRICAÇÃO DE ARTIGOS DE MALHARIA E TRICOTAGEM', '', 'pending_trigger'),
  ('151', '15', 'CURTIMENTO E OUTRAS PREPARAÇÕES DE COURO', '', 'pending_trigger'),
  ('152', '15', 'FABRICAÇÃO DE ARTIGOS PARA VIAGEM E DE ARTEFATOS DIVERSOS DE COURO', '', 'pending_trigger'),
  ('153', '15', 'FABRICAÇÃO DE CALÇADOS', 'Classificam-se os calçados de acordo com o material predominante na confecção do cabedal (couro, sintético, têxtil, etc.), qualquer que seja a natureza dos materiais empregados no forro, solado, etc.', 'pending_trigger'),
  ('750', '75', 'ATIVIDADES VETERINÁRIAS', '', 'pending_trigger'),
  ('154', '15', 'FABRICAÇÃO DE PARTES PARA CALÇADOS, DE QUALQUER MATERIAL', '', 'pending_trigger'),
  ('161', '16', 'DESDOBRAMENTO DE MADEIRA', '', 'pending_trigger'),
  ('162', '16', 'FABRICAÇÃO DE PRODUTOS DE MADEIRA, CORTIÇA E MATERIAL TRANÇADO, EXCETO MÓVEIS', '', 'pending_trigger'),
  ('171', '17', 'FABRICAÇÃO DE CELULOSE E OUTRAS PASTAS PARA A FABRICAÇÃO DE PAPEL', '', 'pending_trigger'),
  ('172', '17', 'FABRICAÇÃO DE PAPEL, CARTOLINA E PAPEL-CARTÃO', '', 'pending_trigger'),
  ('173', '17', 'FABRICAÇÃO DE EMBALAGENS DE PAPEL, CARTOLINA, PAPEL-CARTÃO E PAPELÃO ONDULADO', '', 'pending_trigger'),
  ('174', '17', 'FABRICAÇÃO DE PRODUTOS DIVERSOS DE PAPEL, CARTOLINA, PAPEL-CARTÃO E PAPELÃO ONDULADO', '', 'pending_trigger'),
  ('181', '18', 'ATIVIDADE DE IMPRESSÃO', '', 'pending_trigger'),
  ('182', '18', 'SERVIÇOS DE PRÉ-IMPRESSÃO E ACABAMENTOS GRÁFICOS', '', 'pending_trigger'),
  ('183', '18', 'REPRODUÇÃO DE MATERIAIS GRAVADOS EM QUALQUER SUPORTE', '', 'pending_trigger'),
  ('191', '19', 'COQUERIAS', '', 'pending_trigger'),
  ('192', '19', 'FABRICAÇÃO DE PRODUTOS DERIVADOS DO PETRÓLEO', '', 'pending_trigger'),
  ('193', '19', 'FABRICAÇÃO DE BIOCOMBUSTÍVEIS', '', 'pending_trigger'),
  ('201', '20', 'FABRICAÇÃO DE PRODUTOS QUÍMICOS INORGÂNICOS', '', 'pending_trigger'),
  ('202', '20', 'FABRICAÇÃO DE PRODUTOS QUÍMICOS ORGÂNICOS', '', 'pending_trigger'),
  ('203', '20', 'FABRICAÇÃO DE RESINAS E ELASTÔMEROS', '', 'pending_trigger'),
  ('204', '20', 'FABRICAÇÃO DE FIBRAS ARTIFICIAIS E SINTÉTICAS', '', 'pending_trigger'),
  ('205', '20', 'FABRICAÇÃO DE DEFENSIVOS AGRÍCOLAS E DESINFESTANTES DOMISSANITÁRIOS', '', 'pending_trigger'),
  ('206', '20', 'FABRICAÇÃO DE SABÕES, DETERGENTES, PRODUTOS DE LIMPEZA, COSMÉTICOS, PRODUTOS DE PERFUMARIA E DE HIGIENE PESSOAL', '', 'pending_trigger'),
  ('207', '20', 'FABRICAÇÃO DE TINTAS, VERNIZES, ESMALTES, LACAS E PRODUTOS AFINS', '', 'pending_trigger'),
  ('209', '20', 'FABRICAÇÃO DE PRODUTOS E PREPARADOS QUÍMICOS DIVERSOS', '', 'pending_trigger'),
  ('211', '21', 'FABRICAÇÃO DE PRODUTOS FARMOQUÍMICOS', '', 'pending_trigger'),
  ('212', '21', 'FABRICAÇÃO DE PRODUTOS FARMACÊUTICOS', '', 'pending_trigger'),
  ('221', '22', 'FABRICAÇÃO DE PRODUTOS DE BORRACHA', '', 'pending_trigger'),
  ('222', '22', 'FABRICAÇÃO DE PRODUTOS DE MATERIAL PLÁSTICO', '', 'pending_trigger'),
  ('231', '23', 'FABRICAÇÃO DE VIDRO E DE PRODUTOS DO VIDRO', 'Este grupo compreende a fabricação de vidro plano e de segurança, de embalagens de vidro e de artefatos de vidro para usos diversos e de fibra de vidro e de lã de vidro.  Este grupo não compreende a fabricação de tecidos de fibra de vidro (grupo 13.2); a fabricação de artefatos de plástico reforçados com fibra de vidro (grupo 22.2) e a fabricação de artigos de fibra de vidro (grupo 23.9).', 'pending_trigger'),
  ('232', '23', 'FABRICAÇÃO DE CIMENTO', '', 'pending_trigger'),
  ('233', '23', 'FABRICAÇÃO DE ARTEFATOS DE CONCRETO, CIMENTO, FIBROCIMENTO, GESSO E MATERIAIS SEMELHANTES', '', 'pending_trigger'),
  ('234', '23', 'FABRICAÇÃO DE PRODUTOS CERÂMICOS', '', 'pending_trigger'),
  ('239', '23', 'APARELHAMENTO DE PEDRAS E FABRICAÇÃO DE OUTROS PRODUTOS DE MINERAIS NÃO-METÁLICOS', 'Este grupo compreende o aparelhamento, britamento e outros beneficiamentos em pedras, quando não associados à extração, a fabricação de cal e gesso e a fabricação de produtos diversos de minerais não-metálicos (artefatos de amianto, grafita, fibra de vidro, etc.).', 'pending_trigger'),
  ('241', '24', 'PRODUÇÃO DE FERRO-GUSA E DE FERROLIGAS', '', 'pending_trigger'),
  ('242', '24', 'SIDERURGIA', '', 'pending_trigger'),
  ('243', '24', 'PRODUÇÃO DE TUBOS DE AÇO, EXCETO TUBOS SEM COSTURA', '', 'pending_trigger'),
  ('244', '24', 'METALURGIA DOS METAIS NÃO-FERROSOS', 'Este grupo compreende a metalurgia do alumínio, cobre, estanho, dos metais precisos e de outros metais não-ferrosos e suas ligas, utilizando minério em bruto, materiais intermediários (alumina, p.ex.) e sucata.  Este grupo não compreende a fundição (grupo 24.5) e forjaria (grupo 25.3) de metais não-ferrosos e suas ligas.', 'pending_trigger'),
  ('245', '24', 'FUNDIÇÃO', 'Este grupo compreende as atividades de fundição realizadas sob encomenda, de acordo com especificações próprias.  Este grupo não compreende as operações de fundição realizadas como parte da fabricação de um determinado produto, que se incluem na classe correspondente à da fabricação do produto.', 'pending_trigger'),
  ('251', '25', 'FABRICAÇÃO DE ESTRUTURAS METÁLICAS E OBRAS DE CALDEIRARIA PESADA', '', 'pending_trigger'),
  ('252', '25', 'FABRICAÇÃO DE TANQUES, RESERVATÓRIOS METÁLICOS E CALDEIRAS', '', 'pending_trigger'),
  ('253', '25', 'FORJARIA, ESTAMPARIA, METALURGIA DO PÓ E SERVIÇOS DE TRATAMENTO DE METAIS', 'Este grupo compreende as atividades de forjaria, estamparia, repuxamento e outros tipos de conformação de metais realizadas sob encomenda, de acordo com especificações próprias.  Este grupo não compreende as operações de forjaria, estamparia e a realização de serviços e atividades metalúrgicas em geral realizadas como parte da fabricação de um determinado produto, que se incluem na subclasse correspondente à fabricação do produto.', 'pending_trigger'),
  ('254', '25', 'FABRICAÇÃO DE ARTIGOS DE CUTELARIA, DE SERRALHERIA E FERRAMENTAS', '', 'pending_trigger'),
  ('255', '25', 'FABRICAÇÃO DE EQUIPAMENTO BÉLICO PESADO, ARMAS E MUNIÇÕES', '', 'pending_trigger'),
  ('259', '25', 'FABRICAÇÃO DE PRODUTOS DE METAL NÃO ESPECIFICADOS ANTERIORMENTE', '', 'pending_trigger'),
  ('261', '26', 'FABRICAÇÃO DE COMPONENTES ELETRÔNICOS', '', 'pending_trigger'),
  ('262', '26', 'FABRICAÇÃO DE EQUIPAMENTOS DE INFORMÁTICA E PERIFÉRICOS', 'Este grupo compreende a fabricação e montagem de computadores, como: mainframes, desktops, laptops, servidores etc. e a fabricação de equipamentos periféricos, como impressoras, monitores, teclados, etc.', 'pending_trigger'),
  ('263', '26', 'FABRICAÇÃO DE EQUIPAMENTOS DE COMUNICAÇÃO', 'Este grupo compreende a fabricação de telefones e equipamentos de comunicação de transmissão de sinais e dados por meio de cabos ou ondas eletromagnéticas, tais como os equipamentos de emissão de imagens e sons (televisão e rádio) e outros equipamentos de comunicação sem fios.', 'pending_trigger'),
  ('264', '26', 'FABRICAÇÃO DE APARELHOS DE RECEPÇÃO, REPRODUÇÃO, GRAVAÇÃO E AMPLIFICAÇÃO DE ÁUDIO E VÍDEO', 'Este grupo compreende a fabricação de eletrônicos de consumo como equipamentos de áudio e vídeo para uso doméstico ou em veículos.', 'pending_trigger'),
  ('265', '26', 'FABRICAÇÃO DE APARELHOS E INSTRUMENTOS DE MEDIDA, TESTE E CONTROLE; CRONÔMETROS E RELÓGIOS', 'Este grupo compreende a fabricação de equipamentos de medida, teste, navegação e controle para usos industriais e não-industriais, incluindo aparelhos de medida de tempo como relógios e outros aparelhos relacionados.', 'pending_trigger'),
  ('266', '26', 'FABRICAÇÃO DE APARELHOS ELETROMÉDICOS E ELETROTERAPÊUTICOS E EQUIPAMENTOS DE IRRADIAÇÃO', 'Este grupo compreende a fabricação de aparelhos eletromédicos e eletroterapêuticos e de aparelhos de irradiação para aplicações em diagnóstico médico, médico-terapêutico, industrial, pesquisa e avaliação científica. Irradiação pode ser na forma de raios-beta, raios-gama, raios-X ou outras radiações ionizantes', 'pending_trigger'),
  ('267', '26', 'FABRICAÇÃO DE EQUIPAMENTOS E INSTRUMENTOS ÓPTICOS, FOTOGRÁFICOS E CINEMATOGRÁFICOS', 'Este grupo compreende a fabricação de instrumentos ópticos e lentes (exceto oftálmicas), revestimento, polimento e montagem de lentes (exceto oftálmicas) e a fabricação de equipamentos fotográficos e cinematográficos.', 'pending_trigger'),
  ('268', '26', 'FABRICAÇÃO DE MÍDIAS VIRGENS, MAGNÉTICAS E ÓPTICAS', '', 'pending_trigger'),
  ('271', '27', 'FABRICAÇÃO DE GERADORES, TRANSFORMADORES E MOTORES ELÉTRICOS', '', 'pending_trigger'),
  ('272', '27', 'FABRICAÇÃO DE PILHAS, BATERIAS E ACUMULADORES ELÉTRICOS', '', 'pending_trigger'),
  ('273', '27', 'FABRICAÇÃO DE EQUIPAMENTOS PARA DISTRIBUIÇÃO E CONTROLE DE ENERGIA ELÉTRICA', '', 'pending_trigger'),
  ('274', '27', 'FABRICAÇÃO DE LÂMPADAS E OUTROS EQUIPAMENTOS DE ILUMINAÇÃO', '', 'pending_trigger'),
  ('275', '27', 'FABRICAÇÃO DE ELETRODOMÉSTICOS', '', 'pending_trigger'),
  ('279', '27', 'FABRICAÇÃO DE EQUIPAMENTOS E APARELHOS ELÉTRICOS NÃO ESPECIFICADOS ANTERIORMENTE', '', 'pending_trigger'),
  ('281', '28', 'FABRICAÇÃO DE MOTORES, BOMBAS, COMPRESSORES E EQUIPAMENTOS DE TRANSMISSÃO', '', 'pending_trigger'),
  ('282', '28', 'FABRICAÇÃO DE MÁQUINAS E EQUIPAMENTOS DE USO GERAL', '', 'pending_trigger'),
