  ('295', '29', 'RECONDICIONAMENTO E RECUPERAÇÃO DE MOTORES PARA VEÍCULOS AUTOMOTORES', '', 'pending_trigger'),
  ('301', '30', 'CONSTRUÇÃO DE EMBARCAÇÕES', '', 'pending_trigger'),
  ('303', '30', 'FABRICAÇÃO DE VEÍCULOS FERROVIÁRIOS', '', 'pending_trigger'),
  ('304', '30', 'FABRICAÇÃO DE AERONAVES', '', 'pending_trigger'),
  ('305', '30', 'FABRICAÇÃO DE VEÍCULOS MILITARES DE COMBATE', '', 'pending_trigger'),
  ('309', '30', 'FABRICAÇÃO DE EQUIPAMENTOS DE TRANSPORTE NÃO ESPECIFICADOS ANTERIORMENTE', '', 'pending_trigger'),
