  ('476', '47', 'COMÉRCIO VAREJISTA DE ARTIGOS CULTURAIS, RECREATIVOS E ESPORTIVOS', '', 'pending_trigger'),
  ('477', '47', 'COMÉRCIO VAREJISTA DE PRODUTOS FARMACÊUTICOS, PERFUMARIA E COSMÉTICOS E ARTIGOS MÉDICOS, ÓPTICOS E ORTOPÉDICOS', '', 'pending_trigger'),
  ('478', '47', 'COMÉRCIO VAREJISTA DE PRODUTOS NOVOS NÃO ESPECIFICADOS ANTERIORMENTE E DE PRODUTOS USADOS', '', 'pending_trigger'),
  ('479', '47', 'COMÉRCIO AMBULANTE E OUTROS TIPOS DE COMÉRCIO VAREJISTA', 'Não existe subclasse CNAE para esta classe', 'pending_trigger'),
  ('491', '49', 'TRANSPORTE FERROVIÁRIO E METROFERROVIÁRIO', '', 'pending_trigger'),
  ('492', '49', 'TRANSPORTE RODOVIÁRIO DE PASSAGEIROS', 'Este grupo compreende as atividades de transporte rodoviário, de passageiros e de carga, com ou sem itinerário fixo, abertos ao público ou não, em regime permissionário ou não, sob regime de fretamento, de curta, média ou longa distância.', 'pending_trigger'),
  ('493', '49', 'TRANSPORTE RODOVIÁRIO DE CARGA', 'Este grupo compreende o transporte rodoviário de carga que opera com itinerário definido pelo proprietário da carga ou em seu nome entre os pontos de recepção e de entrega da carga.', 'pending_trigger'),
  ('494', '49', 'TRANSPORTE DUTOVIÁRIO', '', 'pending_trigger'),
  ('495', '49', 'TRENS TURÍSTICOS, TELEFÉRICOS E SIMILARES', '', 'pending_trigger'),
  ('501', '50', 'TRANSPORTE MARÍTIMO DE CABOTAGEM E LONGO CURSO', '', 'pending_trigger'),
  ('502', '50', 'TRANSPORTE POR NAVEGAÇÃO INTERIOR', '', 'pending_trigger'),
  ('503', '50', 'NAVEGAÇÃO DE APOIO', 'Este grupo compreende o transporte de mercadorias e pessoas para suprimento e apoio a navios e a plataformas de pesquisas e exploração de minerais e hidrocarbonetos.', 'pending_trigger'),
  ('509', '50', 'OUTROS TRANSPORTES AQUAVIÁRIOS', '', 'pending_trigger'),
  ('511', '51', 'TRANSPORTE AÉREO DE PASSAGEIROS', '', 'pending_trigger'),
  ('512', '51', 'TRANSPORTE AÉREO DE CARGA', '', 'pending_trigger'),
  ('513', '51', 'TRANSPORTE ESPACIAL', '', 'pending_trigger'),
  ('521', '52', 'ARMAZENAMENTO, CARGA E DESCARGA', '', 'pending_trigger'),
  ('522', '52', 'ATIVIDADES AUXILIARES DOS TRANSPORTES TERRESTRES', '', 'pending_trigger'),
  ('523', '52', 'ATIVIDADES AUXILIARES DOS TRANSPORTES AQUAVIÁRIOS', '', 'pending_trigger'),
  ('524', '52', 'ATIVIDADES AUXILIARES DOS TRANSPORTES AÉREOS', '', 'pending_trigger'),
  ('525', '52', 'ATIVIDADES RELACIONADAS À ORGANIZAÇÃO DO TRANSPORTE DE CARGA', '', 'pending_trigger'),
  ('531', '53', 'ATIVIDADES DE CORREIO', '', 'pending_trigger'),
  ('532', '53', 'ATIVIDADES DE MALOTE E DE ENTREGA', '', 'pending_trigger'),
  ('551', '55', 'HOTÉIS E SIMILARES', 'Este grupo compreende as atividades de alojamento de curta duração em hotéis, motéis, pousadas, com ou sem serviços complementares tais como: restaurantes, auditórios, serviços de comunicação, etc. e outros tipos de alojamento temporário.  Este grupo compreende também o aluguel de imóveis residenciais de curta duração com fins turísticos (aluguel de temporada).  Este grupo não compreende o aluguel de residências com contrato, por período médio ou longo grupo (grupo 68.2).', 'pending_trigger'),
  ('559', '55', 'OUTROS TIPOS DE ALOJAMENTO NÃO ESPECIFICADOS ANTERIORMENTE', '', 'pending_trigger'),
  ('561', '56', 'RESTAURANTES E OUTROS SERVIÇOS DE ALIMENTAÇÃO E BEBIDAS', 'Este grupo compreende as atividades de preparo e fornecimento de alimentação e bebidas em restaurantes, bares, lanchonetes, quiosques e trailers.   Este grupo não compreende os serviços de alimentação associados a espetáculos artísticos (grupo 93.2).', 'pending_trigger'),
  ('562', '56', 'SERVIÇOS DE CATERING, BUFÊ E OUTROS SERVIÇOS DE COMIDA PREPARADA', '', 'pending_trigger'),
  ('772', '77', 'ALUGUEL DE OBJETOS PESSOAIS E DOMÉSTICOS', 'Este grupo compreende o aluguel de bens de uso pessoal e doméstico, bem como o aluguel de equipamentos de esporte e de vídeo. Estas atividades normalmente compreendem o aluguel de bens por um período de curta duração, embora em alguns casos possam envolver contrato de período de tempo mais longo, e são voltadas tanto para pessoas físicas como para empresas.', 'pending_trigger'),
  ('581', '58', 'EDIÇÃO DE LIVROS, JORNAIS, REVISTAS E OUTRAS ATIVIDADES DE EDIÇÃO', 'Este grupo compreende as atividades de edição de livros, jornais, revistas, periódicos, dicionários, enciclopédias, atlas, mapas, listas para malas diretas, listas telefônicas, cadastros e outras publicações, tais como cartões postais, reproduções de trabalhos de arte, etc.  Estas atividades lidam com materiais caracterizados pela criação intelectual no seu desenvolvimento e são usualmente protegidas por direitos autorais.', 'pending_trigger'),
  ('582', '58', 'EDIÇÃO INTEGRADA À IMPRESSÃO DE LIVROS, JORNAIS, REVISTAS E OUTRAS PUBLICAÇÕES', 'Este grupo compreende as atividades de edição integrada à impressão de livros, jornais, revistas, periódicos, dicionários, enciclopédias, atlas, etc. Estas atividades são caracterizadas pela criação intelectual e são usualmente protegidas por direitos autorais.  Este grupo compreende também as atividades de edição integrada à impressão de mapas, listas para malas diretas, listas telefônicas, cadastros, cartões postais, reproduções de trabalhos de arte, etc.', 'pending_trigger'),
  ('591', '59', 'ATIVIDADES CINEMATOGRÁFICAS, PRODUÇÃO DE VÍDEOS E DE PROGRAMAS DE TELEVISÃO', 'Este grupo compreende a produção de filmes em películas, fitas de vídeo, DVD ou em outras mídias para qualquer finalidade; as atividades de apoio, como edição, dublagem, colocação de legendas, etc.; a distribuição e licenciamento de filmes cinematográficos e de outros filmes para as empresas distribuidoras e exibidoras; a exibição de filmes.  Este grupo compreende também a compra e a venda de direitos autorais de filmes cinematográficos e de outros filmes, bem como, os direitos de distribuição dessa produção.  Este grupo não compreende o comércio atacadista de fitas de vídeo e DVDs gravados (grupo 46.4) e o aluguel de fitas de vídeo, DVDs e similares (grupo 77.2).', 'pending_trigger'),
  ('592', '59', 'ATIVIDADES DE GRAVAÇÃO DE SOM E DE EDIÇÃO DE MÚSICA', 'Este grupo compreende a produção de matrizes originais de som em fitas e CDs e a promoção, divulgação e distribuição desse material para o comércio atacadista, varejista e diretamente para o público. A produção das matrizes originais das gravações de som pode ser integrada ou não com as atividades dos estúdios de gravação. O exercício destas atividades requer a obtenção dos direitos para reproduzir e distribuir gravações.  Este grupo compreende também os serviços de gravação de som em estúdios ou outros locais, inclusive a produção de programas de rádio gravados (programas que não são ao vivo). Também estão incluídas neste grupo as atividades de edição musical envolvendo a aquisição e o registro dos direitos autorais de composições musicais; a promoção, autorização e utilização dessas composições em gravações, no rádio, na televisão, no cinema, em apresentações ao vivo, na mídia impressa e em outras mídias.  As unidades que participam destas atividades podem ser proprietárias dos direitos autorais ou atuarem como administradoras desses direitos em nome dos titulares. A atividade de edição de partituras musicais está compreendida neste grupo.', 'pending_trigger'),
  ('601', '60', 'ATIVIDADES DE RÁDIO', '', 'pending_trigger'),
  ('602', '60', 'ATIVIDADES DE TELEVISÃO', 'Este grupo compreende as atividades de definição da programação completa de uma cadeia de televisão, que pode utilizar-se da compra de filmes, documentários e outros componentes dessa programação produzidos por terceiros; de produção realizada pelo próprio canal de televisão (telejornais locais, reportagens ao vivo, etc.); e da combinação de componentes adquiridos de terceiros com os produzidos na própria empresa de televisão.  A programação completa de um canal de televisão pode ser transmitida pela mesma unidade responsável por sua definição ou por terceiros, como as empresas operadoras de televisão a cabo, microondas e satélite.', 'pending_trigger'),
  ('611', '61', 'TELECOMUNICAÇÕES POR FIO', '', 'pending_trigger'),
  ('612', '61', 'TELECOMUNICAÇÕES SEM FIO', '', 'pending_trigger'),
  ('613', '61', 'TELECOMUNICAÇÕES POR SATÉLITE', '', 'pending_trigger'),
  ('614', '61', 'OPERADORAS DE TELEVISÃO POR ASSINATURA', 'Este grupo compreende as atividades das empresas que atuam na captação de sinais de canais contratados e abertos e fazem a distribuição do sinal de programação para os assinantes de televisão mediante transporte por cabo, microondas e satélite.', 'pending_trigger'),
  ('619', '61', 'OUTRAS ATIVIDADES DE TELECOMUNICAÇÕES', '', 'pending_trigger'),
  ('620', '62', 'ATIVIDADES DOS SERVIÇOS DE TECNOLOGIA DA INFORMAÇÃO', '', 'pending_trigger'),
  ('631', '63', 'TRATAMENTO DE DADOS, HOSPEDAGEM NA INTERNET E OUTRAS ATIVIDADES RELACIONADAS', 'Este grupo compreende as atividades de disponibilização de infra-estrutura para os serviços de hospedagem na internet, tratamento de dados e demais atividades relacionadas.  Este grupo compreende também os provedores de conteúdo, os serviços de busca e outros serviços de informação na internet.', 'pending_trigger'),
  ('639', '63', 'OUTRAS ATIVIDADES DE PRESTAÇÃO DE SERVIÇOS DE INFORMAÇÃO', 'Este grupo compreende as atividades das agências de notícias e as demais atividades dedicadas à prestação de serviços de informação.', 'pending_trigger'),
  ('641', '64', 'BANCO CENTRAL', '', 'pending_trigger'),
  ('642', '64', 'INTERMEDIAÇÃO MONETÁRIA - DEPÓSITOS À VISTA', '', 'pending_trigger'),
  ('643', '64', 'INTERMEDIAÇÃO NÃO-MONETÁRIA - OUTROS INSTRUMENTOS DE CAPTAÇÃO', '', 'pending_trigger'),
  ('644', '64', 'ARRENDAMENTO MERCANTIL', '', 'pending_trigger'),
  ('645', '64', 'SOCIEDADES DE CAPITALIZAÇÃO', '', 'pending_trigger'),
  ('646', '64', 'ATIVIDADES DE SOCIEDADES DE PARTICIPAÇÃO', '', 'pending_trigger'),
  ('647', '64', 'FUNDOS DE INVESTIMENTO', '', 'pending_trigger'),
  ('649', '64', 'ATIVIDADES DE SERVIÇOS FINANCEIROS NÃO ESPECIFICADAS ANTERIORMENTE', '', 'pending_trigger'),
  ('651', '65', 'SEGUROS DE VIDA E NÃO-VIDA', '', 'pending_trigger'),
