-- =====================================================================
-- MIGRATION 0014 — Seed CNAE 2.3 (1.332 subclasses) — IBGE/CONCLA
-- =====================================================================
-- IMPORTANTE: aplicar 0013_cnae_referencia.sql ANTES deste arquivo.
-- O hash_conteudo será recalculado pelo trigger trg_*_set_hash.
-- =====================================================================

BEGIN;

-- ┌── SEÇÕES (21 registros) ──┐
ON CONFLICT (secao_id) DO UPDATE SET
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

-- ┌── DIVISÕES (87 registros) ──┐
ON CONFLICT (divisao_id) DO UPDATE SET
  secao_id = EXCLUDED.secao_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

-- ┌── GRUPOS (285 registros) ──┐
ON CONFLICT (grupo_id) DO UPDATE SET
  divisao_id = EXCLUDED.divisao_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (grupo_id) DO UPDATE SET
  divisao_id = EXCLUDED.divisao_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

-- ┌── CLASSES (673 registros) ──┐
ON CONFLICT (classe_id) DO UPDATE SET
  grupo_id = EXCLUDED.grupo_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (classe_id) DO UPDATE SET
  grupo_id = EXCLUDED.grupo_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (classe_id) DO UPDATE SET
  grupo_id = EXCLUDED.grupo_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (classe_id) DO UPDATE SET
  grupo_id = EXCLUDED.grupo_id,
  descricao = EXCLUDED.descricao,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

-- ┌── SUBCLASSES (1.332 registros) ──┐
ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

ON CONFLICT (subclasse_id) DO UPDATE SET
  classe_id = EXCLUDED.classe_id,
  descricao = EXCLUDED.descricao,
  atividades = EXCLUDED.atividades,
  observacoes = EXCLUDED.observacoes,
  updated_at = NOW();

-- Validação pós-seed
DO $$
DECLARE qtd_sec INT; qtd_div INT; qtd_gru INT; qtd_cla INT; qtd_sub INT;
BEGIN
    SELECT COUNT(*) INTO qtd_sec FROM qdi.cnae_secao;
    SELECT COUNT(*) INTO qtd_div FROM qdi.cnae_divisao;
    SELECT COUNT(*) INTO qtd_gru FROM qdi.cnae_grupo;
    SELECT COUNT(*) INTO qtd_cla FROM qdi.cnae_classe;
    SELECT COUNT(*) INTO qtd_sub FROM qdi.cnae_subclasse;
    RAISE NOTICE 'CNAE 2.3 importada: % seções, % divisões, % grupos, % classes, % subclasses',
        qtd_sec, qtd_div, qtd_gru, qtd_cla, qtd_sub;
    IF qtd_sec <> 21  THEN RAISE EXCEPTION 'Esperado 21 seções, encontrado %',  qtd_sec; END IF;
    IF qtd_div <> 87  THEN RAISE EXCEPTION 'Esperado 87 divisões, encontrado %', qtd_div; END IF;
    IF qtd_gru <> 285 THEN RAISE EXCEPTION 'Esperado 285 grupos, encontrado %',  qtd_gru; END IF;
    IF qtd_cla <> 673 THEN RAISE EXCEPTION 'Esperado 673 classes, encontrado %', qtd_cla; END IF;
    IF qtd_sub <> 1332 THEN RAISE EXCEPTION 'Esperado 1332 subclasses, encontrado %', qtd_sub; END IF;
END $$;

COMMIT;

-- ============================================================================
-- FIM DA MIGRATION 0014 — CNAE 2.3 SEED
-- ============================================================================